const TRAIT_LABELS={creation:'Criação',finishing:'Finalização',defending:'Defesa',aerial:'Bola aérea',transition:'Transição',setPiece:'Bola parada',leadership:'Liderança',penalties:'Pênaltis'};
function playerTraits(p){return Array.isArray(p&&p.traits)?p.traits.filter(Boolean):[]}
function traitText(p){const tr=playerTraits(p);return tr.length?tr.join(' · '):'sem característica'}
function traitChipsHtml(p,limit=4){const tr=playerTraits(p).slice(0,limit);return tr.length?`<span class="trait-line">${tr.map(t=>`<em>${esc(t)}</em>`).join('')}</span>`:''}
function posFactorForBucket(pos,bucket){const g=groupOf(pos);if(bucket==='finishing')return g==='att'?1.28:g==='mid'?0.92:g==='def'?0.45:0.20;if(bucket==='creation')return g==='mid'?1.18:g==='att'?1.02:g==='def'?0.78:0.40;if(bucket==='defending')return g==='def'?1.20:g==='gk'?1.12:g==='mid'?0.98:0.42;if(bucket==='aerial')return g==='def'?1.16:g==='att'?1.08:g==='gk'?0.90:0.68;if(bucket==='transition')return g==='att'?1.10:g==='mid'?1.06:g==='def'?0.90:0.55;if(bucket==='setPiece')return g==='mid'?1.10:g==='def'?1.00:g==='att'?0.92:0.25;if(bucket==='leadership')return g==='mid'?1.10:g==='def'?1.02:g==='gk'?1.00:0.82;if(bucket==='penalties')return g==='gk'?1.18:g==='att'?1.08:g==='mid'?0.95:0.70;return 1}
function traitBucketScore(fs,bucket){const wanted=new Set(TRAIT_BUCKETS[bucket]||[]);let vals=[];fs.forEach(s=>{const p=s.player;if(!p)return;playerTraits(p).forEach(t=>{if(wanted.has(t)){let v=clamp((p.adjusted||p.rating||75)-60,8,42)*posFactorForBucket(s.pos,bucket);if(t==='Pegador de pênaltis'&&bucket==='penalties')v*=1.50;if(t==='Finalização'&&bucket==='finishing')v*=1.18;if(t==='Presença de área'&&bucket==='finishing')v*=1.10;if(t==='Criatividade'&&bucket==='creation')v*=1.12;if(t==='Passes'&&bucket==='creation')v*=1.06;if(t==='Desarme'&&bucket==='defending')v*=1.10;if(t==='Antecipação'&&bucket==='defending')v*=1.08;if(t==='Bola parada'&&bucket==='setPiece')v*=1.24;if(t==='Liderança'&&bucket==='leadership')v*=1.18;if(t==='Muralha'&&(bucket==='leadership'||bucket==='defending'))v*=1.14;vals.push(v)}})});if(!vals.length)return 45;vals.sort((a,b)=>b-a);const decay=[1,.62,.38,.24,.16,.10,.07,.05];const total=vals.reduce((a,v,i)=>a+v*(decay[i]||.035),0);return Math.round(clamp(48+total*.82,35,100))}
function hasTraitIn(fs,traits,groups=null){const want=new Set(traits);return fs.some(s=>{if(groups&&!groups.includes(groupOf(s.pos)))return false;return playerTraits(s.player).some(t=>want.has(t))})}
function teamTraitIdentity(fs){const scores={};Object.keys(TRAIT_BUCKETS).forEach(k=>scores[k]=traitBucketScore(fs,k));const uniqueTraits=[...new Set(fs.flatMap(s=>playerTraits(s.player)))];const missing=[];if(!hasTraitIn(fs,['Finalização','Presença de área'],['att','mid']))missing.push('falta um definidor claro');if(!hasTraitIn(fs,['Criatividade','Passes','Assistência'],['mid','att']))missing.push('falta criação organizada');if(!hasTraitIn(fs,['Desarme','Antecipação'],['def','mid']))missing.push('falta combate e leitura defensiva');if(!hasTraitIn(fs,['Bola Aérea','Saída do gol'],['def','gk','att']))missing.push('bola aérea vulnerável');if(!hasTraitIn(fs,['Liderança','Muralha']))missing.push('falta liderança nos jogos grandes');const sorted=Object.entries(scores).sort((a,b)=>b[1]-a[1]);const diversity=clamp(55+uniqueTraits.length*4+sorted.filter(x=>x[1]>=75).length*3-missing.length*4,35,100);return {scores,uniqueTraits,missing,diversity:Math.round(diversity),top:sorted.slice(0,3).map(([k,v])=>({key:k,label:TRAIT_LABELS[k],score:v}))}}
function identityMiniHtml(identity){if(!identity||!identity.scores)return '';const s=identity.scores;return `<div class="identity-grid"><div><span>Criação</span><b>${s.creation}</b></div><div><span>Finalização</span><b>${s.finishing}</b></div><div><span>Defesa</span><b>${s.defending}</b></div><div><span>Bola aérea</span><b>${s.aerial}</b></div><div><span>Bola parada</span><b>${s.setPiece}</b></div><div><span>Liderança</span><b>${s.leadership}</b></div></div>${identity.missing&&identity.missing.length?`<p class="profile-text trait-warning">Atenção: ${esc(identity.missing.slice(0,2).join(' · '))}.</p>`:''}`}
function traitMod(score,scale=.08){return ((score||70)-72)*scale}
function describeTraitShort(k,score){if(score>=88)return `${TRAIT_LABELS[k]} forte`;if(score>=74)return `${TRAIT_LABELS[k]} funcional`;if(score<=58)return `${TRAIT_LABELS[k]} fraca`;return `${TRAIT_LABELS[k]} instável`}
function eventKindFor(side,identity){if(side!=='user'||!identity)return Math.random()<.18?'set':(Math.random()<.35?'cross':Math.random()<.52?'counter':'open');const s=identity.scores||{};const pool=[['open',Math.max(15,s.creation||60)],['cross',Math.max(10,(s.aerial||60)+(s.creation||60)*.25)],['counter',Math.max(10,s.transition||60)],['set',Math.max(8,s.setPiece||55)]];return weighted(pool,x=>x[1])[0]}
function chanceText(kind,side,opp){if(side==='opp')return `${opponentLabel(opp)} pressiona, LaBestia resiste.`;if(kind==='cross')return 'A Besta cria pelo lado e procura presença na área.';if(kind==='counter')return 'A Besta acelera a transição e pega o rival aberto.';if(kind==='set')return 'Bola parada perigosa para o LaBestia.';return `${scorer()} tenta criar, mas a defesa corta.`}

