function benchGroupLabel(g){return g==='G'?'goleiro':g==='def'?'defesa':g==='mid'?'meio-campo':'ataque'}

const SAVE_KEY='labestia.save.v4';
const LAST_KEY='labestia.last.v2';
const RANK_KEY='labestia.ranking.v2';
const ACH_KEY='labestia.achievements.v2';
function safeParse(v,fallback=null){try{return JSON.parse(v)}catch(e){return fallback}}
function serializeTournament(t){
  if(!t)return null;
  const clone={...t};
  clone.used=t.used?[...t.used]:[];
  clone.match=null;
  clone.penalties=null;
  return clone;
}
function hydrateTournament(t){
  if(!t)return null;
  t.used=new Set(t.used||[]);
  t.match=null;
  t.penalties=null;
  return t;
}
function serializableState(){return {
  formationName:state.formationName,
  slots:state.slots,
  candidates:state.candidates,
  selectedCandidate:state.selectedCandidate,
  movingSlot:null,
  rerolls:state.rerolls,
  rolling:false,
  tournament:serializeTournament(state.tournament),
  seenLost:[...state.seenLost],
  roundStarted:state.roundStarted,
  captainPicked:state.captainPicked
}}
function saveProgress(){
  if(!DATA_READY)return;
  try{localStorage.setItem(SAVE_KEY,JSON.stringify(serializableState()));updateSavedUi()}catch(e){}
}
function clearProgress(){try{localStorage.removeItem(SAVE_KEY);updateSavedUi()}catch(e){}}
function hasSavedProgress(){const s=safeParse(localStorage.getItem(SAVE_KEY));return !!(s&&s.slots&&s.slots.length)}
function loadProgress(){
  const s=safeParse(localStorage.getItem(SAVE_KEY));
  if(!s||!s.slots)return false;
  clearDraftCaches();
  state.formationName=s.formationName||'4-3-3';
  state.slots=s.slots||[];
  state.candidates=s.candidates||[];
  state.selectedCandidate=s.selectedCandidate||null;
  state.movingSlot=null;
  state.rerolls=Number.isFinite(s.rerolls)?s.rerolls:1;
  state.rolling=false;
  state.tournament=hydrateTournament(s.tournament);
  state.seenLost=new Set(s.seenLost||[]);
  state.roundStarted=!!s.roundStarted;
  state.captainPicked=!!s.captainPicked;
  if($('formationSelect'))$('formationSelect').value=state.formationName;
  renderFormationCards();renderAll();updateSavedUi();
  return true;
}
function continueSavedCampaign(){
  if(!loadProgress()){toast('Nenhuma campanha salva encontrada.');return}
  $('startOverlay').style.display='none';
  toast('Campanha restaurada. A América ainda cobra.');
  if(state.tournament)openTournament();
}
function updateSavedUi(){
  const has=hasSavedProgress();
  ['continueBtn','homeContinueBtn'].forEach(id=>{const b=$(id);if(b)b.style.display=has?'inline-flex':'none'});
}
function saveLastCampaign(summary){try{localStorage.setItem(LAST_KEY,JSON.stringify(summary))}catch(e){}}
function getRanking(){return safeParse(localStorage.getItem(RANK_KEY),[])||[]}
function saveRanking(arr){try{localStorage.setItem(RANK_KEY,JSON.stringify(arr.slice(0,10)))}catch(e){}}
function campaignScore(summary){return (summary.champ?10000:0)+(summary.worldChampion?2500:(summary.worldPlayed?650:0))+summary.wins*340+summary.draws*120-summary.losses*80+summary.overall*12+summary.fit*9+summary.chemistry*5+(summary.goalsFor||0)*25-(summary.goalsAgainst||0)*18}
function addRanking(summary){const item={...summary,score:campaignScore(summary),date:new Date().toISOString()};const arr=getRanking();arr.push(item);arr.sort((a,b)=>b.score-a.score);saveRanking(arr);return item}
function rankingHtml(limit=10){const arr=getRanking().slice(0,limit);if(!arr.length)return '<div class="history-item">Ainda não há campanhas salvas neste navegador.</div>';return `<div class="ranking-list">${arr.map((r,i)=>`<div class="ranking-row"><b>#${i+1}</b><span>${esc(r.status)}</span><small>${r.wins}V ${r.draws}E ${r.losses}D · Força ${Math.round(r.overall)} · Encaixe ${Math.round(r.fit)} · ${Math.round(r.score)} pts</small></div>`).join('')}</div>`}
function openRanking(){
  $('tournamentModal').classList.add('open');
  $('modalSub').textContent='Melhores campanhas neste navegador';
  $('tournamentContent').innerHTML=`<div class="final-banner">Ranking local da Besta</div><div class="campaign"><div class="panel"><h3>Top campanhas</h3>${rankingHtml(10)}<div class="toolbar"><button class="btn-primary" onclick="closeTournament()">Fechar</button></div></div><div class="panel"><h3>Como pontua?</h3><p class="small">Título, vitórias, força, encaixe, entrosamento, saldo ofensivo e poucos gols sofridos aumentam a pontuação. Derrotas e defesa vazada derrubam a nota.</p></div></div>`;
}
