function getEarnedAchievements(){return new Set(safeParse(localStorage.getItem(ACH_KEY),[])||[])}
function saveEarnedAchievements(set){try{localStorage.setItem(ACH_KEY,JSON.stringify([...set]))}catch(e){}}
function evaluateAchievements(summary){const earned=getEarnedAchievements(),newOnes=[];ACHIEVEMENTS.forEach(a=>{if(a.test(summary)){if(!earned.has(a.id))newOnes.push(a);earned.add(a.id)}});saveEarnedAchievements(earned);return {earned,newOnes}}
function achievementsHtml(summary=null){const earned=summary?evaluateAchievements(summary).earned:getEarnedAchievements();return `<div class="ach-grid">${ACHIEVEMENTS.map(a=>`<div class="ach-card ${earned.has(a.id)?'earned':'locked'}"><b>${esc(a.name)}</b><span>${esc(a.desc)}</span></div>`).join('')}</div>`}
function campaignSummary(){
  const t=state.tournament,st=t.stats||teamStats();
  const scorers=t.scorers||{};
  let topName='—',topGoals=0;Object.entries(scorers).forEach(([n,g])=>{if(g>topGoals){topName=n;topGoals=g}});
  const champ=String(t.outcome||'').includes('Campeão');
  const world=t.world||null;
  return {status:t.outcome||'Campanha encerrada',champ,wins:t.record?.v||0,draws:t.record?.e||0,losses:t.record?.d||0,overall:Math.round(st.overall||0),attack:Math.round(st.attack||0),mid:Math.round(st.mid||0),defense:Math.round(st.defense||0),fit:Math.round(st.fit||0),chemistry:Math.round(st.chemistry||0),bestDecade:st.bestDecade,bestCount:st.bestCount||0,goalsFor:t.goalsFor||0,goalsAgainst:t.goalsAgainst||0,topScorer:topGoals?`${topName} (${topGoals})`:'—',penaltyWins:t.penaltyWins||0,transfersMade:t.transfersMade||0,benchUsedTotal:t.benchUsedTotal||0,morale:Math.round(t.morale??80),finalVenue:t.finalVenue||null,worldPlayed:!!(world&&world.played),worldChampion:!!(world&&world.won),worldOpponent:world&&world.opp?opponentLabel(world.opp):'',worldScore:world&&world.score?world.score:null,noNaturalGoalkeeper:!!(st.counts&&st.counts.gk===0),history:[...(t.history||[])].slice(0,12)};
}
function finalVerdict(s){
  if(s.worldChampion)return 'Depois da América, a Besta encarou o PSG e pintou o mundo de azul.';
  if(s.worldPlayed&&s.champ)return 'A América foi conquistada, mas o PSG cobrou caro no Mundial.';
  if(s.champ&&s.fit>=92)return 'Foi uma Besta organizada: talento, encaixe e casca continental.';
  if(s.champ)return 'Não foi a Besta mais perfeita. Foi a mais cascuda.';
  if(!s.champ&&s.overall>=95&&s.fit<80)return 'Overall alto não salvou um time torto. A América cobrou o improviso.';
  if(!s.champ&&s.defense<84)return 'A campanha morreu onde a Libertadores mais cobra: na defesa.';
  return 'A Besta competiu, mas a América encontrou uma fresta.';
}

const FIT_CACHE=new Map();
const BEST_FIT_CACHE=new Map();
function openSlotsKey(){return state.slots.filter(s=>!s.player).map(s=>s.idx+':'+s.pos).join('|')}
function clearDraftCaches(){BEST_FIT_CACHE.clear()}
function playerNorm(p){return p._norm||(p._norm=norm(p.name))}
function toggleLiteMode(){document.body.classList.toggle('lite-mode');const on=document.body.classList.contains('lite-mode');try{localStorage.setItem('labestiaLiteMode',on?'1':'0')}catch(e){};const b=$('liteBtn');if(b)b.textContent=on?'Modo normal':'Modo leve'}
function applySavedLiteMode(){let on=false;try{on=localStorage.getItem('labestiaLiteMode')==='1'}catch(e){};if(on)document.body.classList.add('lite-mode');const b=$('liteBtn');if(b)b.textContent=on?'Modo normal':'Modo leve'}
async function init(){
  applySavedLiteMode();
  try{await loadGameData()}catch(err){
    console.error(err);
    const box=$('statusText');
    if(box)box.textContent='Erro ao carregar dados. No GitHub Pages funciona automaticamente; localmente use um servidor.';
    const start=$('startOverlay');
    if(start)start.innerHTML='<div class="start-panel"><h1>LaBestia</h1><p>Não consegui carregar a base de dados. Publique no GitHub Pages ou rode com um servidor local.</p></div>';
    return;
  }
  Object.keys(FORMATIONS).forEach(f=>{const o=document.createElement('option');o.value=f;o.textContent=f;$('formationSelect').appendChild(o)});
  renderFormationCards();
  setFormation('4-3-3',true);
  renderAll();
  updateSavedUi();
}
document.addEventListener('DOMContentLoaded',init);
function renderFormationCards(){const box=$('startFormations');if(box)box.innerHTML=Object.entries(FORMATIONS).map(([name,arr])=>`<div class="formation-card ${name===state.formationName?'active':''}" onclick="setFormation('${name}',true)"><b>${name}</b><span>${arr.map(p=>POS_LABEL[p]).join(' · ')}</span></div>`).join('');renderFormationPreview()}
function renderFormationPreview(){const box=$('formationPreview');if(!box)return;const coords=coordsFor(state.formationName);box.innerHTML=`<div class="preview-pitch">${state.slots.map((s,i)=>`<div class="preview-slot" style="left:${coords[i][0]}%;top:${coords[i][1]}%">${POS_LABEL[s.pos]}</div>`).join('')}</div><div class="preview-title">${state.formationName}</div>`}
function setFormation(name,initial=false){clearDraftCaches();state.formationName=name;state.slots=FORMATIONS[name].map((pos,i)=>({id:'s'+i,pos,player:null,idx:i}));state.candidates=[];state.selectedCandidate=null;state.movingSlot=null;state.rerolls=1;state.rolling=false;state.tournament=null;state.seenLost=new Set();state.roundStarted=false;state.captainPicked=false;if($('formationSelect'))$('formationSelect').value=name;renderFormationCards();renderAll();if(!initial&&$('startOverlay').style.display==='none')toast('Formação alterada. O draft recomeçou.')}
function resetGame(){clearProgress();setFormation(state.formationName);$('startOverlay').style.display='grid';updateSavedUi()}function startGame(){$('startOverlay').style.display='none';rollDraft();saveProgress()}
function selectedNames(){return new Set(state.slots.filter(s=>s.player).map(s=>playerNorm(s.player)))}function filled(){return state.slots.filter(s=>s.player)}function emptySlots(){return state.slots.filter(s=>!s.player)}function isComplete(){return filled().length===state.slots.length}function roundNumber(){return Math.min(filled().length+1,11)}
function groupOf(pos){if(pos==='G')return 'gk';if(['LD','ZG','LE'].includes(pos))return 'def';if(['VOL','MEI','MD','ME'].includes(pos))return 'mid';return 'att'}
function penaltyFor(pos,p){const pp=[...(p.positions||[]),p.primary].filter(Boolean);if(pos==='G'){return pp.includes('G')?0:.70}if(pp.includes('G'))return null;if(pp.includes(pos))return 0;const wingPairs={ME:'PE',PE:'ME',MD:'PD',PD:'MD'};if(wingPairs[pos]&&pp.includes(wingPairs[pos]))return .01;const near={ME:['PE','LE','MEI','VOL'],MD:['PD','LD','MEI','VOL'],PE:['ME','ATA','PD','LE'],PD:['MD','ATA','PE','LD'],LD:['MD','ZG','LE'],LE:['ME','ZG','LD'],ZG:['LD','LE','VOL'],VOL:['MEI','ZG','MD','ME'],MEI:['VOL','ATA','ME','MD'],ATA:['PE','PD','MEI']};if((near[pos]||[]).some(x=>pp.includes(x)))return .10;if(pp.some(x=>groupOf(x)===groupOf(pos)))return .20;return .35}
function fitFor(p,pos){const key=(p.id||p.name)+'|'+pos+'|'+(p.rating||0);if(FIT_CACHE.has(key))return FIT_CACHE.get(key);const pen=penaltyFor(pos,p);let out;if(pen===null)out={allowed:false,penalty:null,adjusted:0,label:'não permitido'};else{let label=pen===0?'natural':pen<=.01?'quase natural':pen<=.05?'quase natural':pen===.10?'adaptado':pen===.20?'improviso':'emergência';if(pen>=.70)label='goleiro de emergência';out={allowed:true,penalty:pen,adjusted:Math.round(p.rating*(1-pen)),label}}FIT_CACHE.set(key,out);return out}
function bestFitForOpen(p){const key=(p.id||p.name)+'|'+openSlotsKey();if(BEST_FIT_CACHE.has(key))return BEST_FIT_CACHE.get(key);let fits=emptySlots().map(s=>({slot:s,...fitFor(p,s.pos)})).filter(f=>f.allowed);fits.sort((a,b)=>a.penalty-b.penalty||b.adjusted-a.adjusted);const out=fits[0]||null;BEST_FIT_CACHE.set(key,out);return out}
function rarityClass(p){if(p.rating>=95)return 'legend';if(p.rating>=90)return 'craque';if(p.rating<78)return 'weak';return ''}function rarityName(p){if(p.rating>=97)return 'Lenda absoluta';if(p.rating>=95)return 'Lenda';if(p.rating>=90)return 'Craque';if(p.rating>=85)return 'Muito forte';if(p.rating>=80)return 'Útil';if(p.rating>=70)return 'Risco';return 'Desespero'}
function poolPlayers(){const names=selectedNames();let arr=PLAYERS.filter(p=>!names.has(playerNorm(p))&&bestFitForOpen(p));let fresh=arr.filter(p=>!state.seenLost.has(p.id));if(fresh.length>=20)return fresh;return arr}
function baseWeight(p){if(p.rating>=97)return .014;if(p.rating>=95)return .028;if(p.rating>=93)return .060;if(p.rating>=90)return .135;if(p.rating>=85)return .55;if(p.rating>=80)return 1;if(p.rating>=70)return 1.18;return .72}
function needTarget(){const open=emptySlots();const weights=open.map(s=>{let w=1;if(s.pos==='G')w+=3;if(['LD','LE','ZG'].includes(s.pos))w+=1.4;if(['MD','ME'].includes(s.pos))w+=.9;return [s,w]});return weighted(weights.map(x=>x[0]),s=>weights.find(y=>y[0]===s)[1])}
function pickForPosition(pos,mode='need',exclude=new Set()){let arr=poolPlayers().filter(p=>!exclude.has(p.id)).map(p=>({p,fit:fitFor(p,pos)})).filter(x=>x.fit.allowed);if(mode==='need')arr=arr.filter(x=>x.fit.penalty<=.20);if(mode==='safe')arr=arr.filter(x=>x.p.rating<=88&&x.fit.penalty<=.20);if(!arr.length)return null;return weighted(arr,x=>{let w=baseWeight(x.p); if(x.fit.penalty===0)w*=2.4; else if(x.fit.penalty<=.1)w*=1.35; if(mode==='safe'&&x.p.rating>=75&&x.p.rating<=86)w*=2.0; return w}).p}
function pickForcedForOpenSlot(slot,exclude=new Set()){let arr=poolPlayers().filter(p=>!exclude.has(p.id)).map(p=>({p,fit:fitFor(p,slot.pos)})).filter(x=>x.fit.allowed);if(!arr.length)return null;const natural=arr.filter(x=>x.fit.penalty===0), adapted=arr.filter(x=>x.fit.penalty<=.10), acceptable=arr.filter(x=>x.fit.penalty<=.20);arr=natural.length?natural:(adapted.length?adapted:(acceptable.length?acceptable:arr));return weighted(arr,x=>{let w=baseWeight(x.p); if(x.fit.penalty===0)w*=3.2; else if(x.fit.penalty<=.10)w*=1.8; else if(x.fit.penalty<=.20)w*=1.0; return w}).p}
function pickRandom(mode='mixed',exclude=new Set()){let arr=poolPlayers().filter(p=>!exclude.has(p.id));if(!arr.length)return null;if(mode==='temptation'){let hi=arr.filter(p=>p.rating>=88);arr=hi.length?hi:arr;return weighted(arr,p=>baseWeight(p)*Math.pow(Math.max(1,p.rating-82),1.10)*(p.rating>=95?.38:1))}if(mode==='strong'){let hi=arr.filter(p=>p.rating>=85);arr=hi.length?hi:arr;return weighted(arr,p=>Math.pow(Math.max(1,p.rating-78),.85)*baseWeight(p)*(p.rating>=95?.45:1))}if(mode==='weak'){let lo=arr.filter(p=>p.rating<=84);arr=lo.length?lo:arr;return weighted(arr,p=>(104-p.rating)*baseWeight(p))}return weighted(arr,p=>baseWeight(p))}
function captainWeight(p){if(p.rating>=97)return .10;if(p.rating>=95)return .22;if(p.rating>=93)return .55;if(p.rating>=90)return 1.25;return 0}
function generateCaptainOptions(){const list=[],ex=new Set();const groups=shuffle(['G','def','mid','att','any']);function poolByGroup(g){let arr=poolPlayers().filter(p=>p.rating>=90&&!ex.has(p.id));if(g==='any')return arr;if(g==='G')return arr.filter(p=>[...(p.positions||[]),p.primary].includes('G'));return arr.filter(p=>[...(p.positions||[]),p.primary].some(pos=>groupOf(pos)===g))}function tryCaptain(g){let arr=poolByGroup(g);if(!arr.length)return false;const p=weighted(arr,captainWeight);if(addCandidate(list,p,'capitão')){ex.add(p.id);return true}return false}groups.forEach(g=>{if(list.length<5)tryCaptain(g)});while(list.length<5){if(!tryCaptain('any'))break}return list.slice(0,5).map(c=>({...c,captainOffer:true,offerTag:'capitão'}))}
function addCandidate(list,p,tag){if(!p||list.some(x=>x.id===p.id)||list.some(x=>norm(x.name)===norm(p.name)&&x.decade===p.decade))return false;const best=bestFitForOpen(p);if(!best)return false;list.push({...p,offerTag:tag,bestPos:best.slot.pos,bestPenalty:best.penalty,bestAdjusted:best.adjusted,bestLabel:best.label,rarity:rarityName(p)});return true}
function generateDraftOptions(){if(!state.captainPicked&&filled().length===0)return generateCaptainOptions();const list=[],ex=new Set();const open=emptySlots();const golden=Math.random()<.035;const cruel=!golden&&Math.random()<.16;function tryAdd(p,tag){if(addCandidate(list,p,tag)){ex.add(p.id);return true}return false}
  // Regra fixa: toda mão precisa trazer pelo menos uma opção que resolva uma posição vaga.
  let forced=false;for(const s of shuffle(open)){if(tryAdd(pickForcedForOpenSlot(s,ex),'posição vaga')){forced=true;break}}
  if(!forced){for(const s of shuffle(open)){if(tryAdd(pickForPosition(s.pos,'need',ex),'necessidade'))break}}
  const extraNeed=open.length<=3?2:(open.length<=5?1:0);for(let i=0;i<extraNeed;i++){for(const s of shuffle(open)){if(tryAdd(pickForPosition(s.pos,'safe',ex),'segurança'))break}}
  if(Math.random()<.48){tryAdd(pickRandom('temptation',ex),'tentação')}
  while(list.length<5){let r=Math.random();const mode=golden?'strong':(cruel?'weak':(r<.42?'mixed':r<.68?'weak':r<.90?'strong':'temptation'));let p=pickRandom(mode,ex);if(!tryAdd(p,mode==='strong'?'forte':mode==='weak'?'risco':mode==='temptation'?'tentação':'livre')){break}}return list.slice(0,5)}
function rollDraft(){if(state.rolling||isComplete())return;if(state.candidates&&state.candidates.length){toast('Você já tem uma mão ativa. Escolha uma carta ou use a troca de mão.');return}state.rolling=true;state.candidates=[];state.selectedCandidate=null;state.roundStarted=true;renderOptions();$('rollStrip').classList.add('rolling');$('rollBtn').disabled=true;$('rerollBtn').disabled=true;let ticks=0;const anim=(!state.captainPicked&&filled().length===0)?poolPlayers().filter(p=>p.rating>=90):poolPlayers();const iv=setInterval(()=>{const p=sample(anim)||sample(PLAYERS);$('rollMain').textContent=p?p.name:'Role';$('rollSub').textContent=p?`${p.decade} · ${allPos(p)} · ${p.rating}`:'cinco cartas';ticks++;if(ticks>20){clearInterval(iv);state.candidates=generateDraftOptions();state.rolling=false;$('rollStrip').classList.remove('rolling');$('rollBtn').disabled=true;$('rerollBtn').disabled=state.rerolls<=0||(!state.captainPicked&&filled().length===0);renderAll();saveProgress()}},56)}
function rerollDraft(){if((!state.captainPicked&&filled().length===0)||state.rerolls<=0||state.rolling||isComplete())return;if(state.candidates.length)state.candidates.forEach(c=>state.seenLost.add(c.id));state.rerolls--;toast('Troca de mão usada. Agora vai até o fim.');state.candidates=[];state.selectedCandidate=null;rollDraft()}
function chooseCandidate(id){const c=state.candidates.find(x=>x.id===Number(id));if(!c)return;state.selectedCandidate=c;state.movingSlot=null;renderOptions();renderSelectedTray();renderPitch();toast(`${c.name}: escolha a posição no campo.`)}
function placeCandidate(id,slotIdx){const p=state.candidates.find(x=>x.id===Number(id));const slot=state.slots[slotIdx];if(!p||!slot)return;if(slot.player){toast('Esta posição já está ocupada. Arraste jogadores escalados para reorganizar.');return}const fit=fitFor(p,slot.pos);if(!fit.allowed){toast('Goleiro não pode jogar na linha.');return}slot.player={...p,assigned:slot.pos,penalty:fit.penalty,adjusted:fit.adjusted,fitLabel:fit.label,captain:p.captainOffer||(!state.captainPicked&&filled().length===0)};if(slot.player.captain)state.captainPicked=true;state.candidates.forEach(c=>{if(c.id!==p.id)state.seenLost.add(c.id)});state.candidates=[];state.selectedCandidate=null;state.movingSlot=null;clearDraftCaches();renderAll();saveProgress();if(isComplete())toast('Equipe completa. A América espera.');else setTimeout(()=>rollDraft(),420)}
function moveSlot(from,to){if(from===to)return;const a=state.slots[from],b=state.slots[to];if(!a?.player||!b)return;const pa=a.player,pb=b.player;const fita=fitFor(pa,b.pos);if(!fita.allowed){toast('Goleiro não pode jogar na linha.');return}if(pb){const fitb=fitFor(pb,a.pos);if(!fitb.allowed){toast('Troca inválida.');return}a.player={...pb,assigned:a.pos,penalty:fitb.penalty,adjusted:fitb.adjusted,fitLabel:fitb.label};b.player={...pa,assigned:b.pos,penalty:fita.penalty,adjusted:fita.adjusted,fitLabel:fita.label};}else{a.player=null;b.player={...pa,assigned:b.pos,penalty:fita.penalty,adjusted:fita.adjusted,fitLabel:fita.label};}state.movingSlot=null;clearDraftCaches();renderAll()}
function renderAll(){renderDraw();renderPitch();renderOptions();renderSelectedTray();renderBox();renderNeedTags();renderFormationPreview()}
function renderSelectedTray(){const tray=$('selectedTray');if(!tray)return;const c=state.selectedCandidate;if(!c){tray.className='selected-tray';tray.innerHTML='<div class="tray-empty">Toque numa carta. Depois toque numa posição destacada no campo, ou arraste se preferir.</div>';return}tray.className='selected-tray ready';tray.innerHTML=`<div class="tray-card" draggable="true" data-id="${c.id}"><div><b>${esc(c.name)}</b><span>${esc(allPos(c))} · ${esc(c.decade)} · ${esc(c.offerTag||c.rarity||'opção')}</span></div><div class="tray-ovr">${c.rating}</div></div>`;const card=tray.querySelector('.tray-card');card.addEventListener('dragstart',ev=>{ev.dataTransfer.setData('text/plain','candidate:'+c.id)})}
function renderDraw(){$('rerolls').textContent=state.rerolls;const rw=$('rerollWarning');if(rw){rw.className='reroll-warning '+(state.rerolls<=0?'used':'');rw.innerHTML=state.rerolls>0?'Você tem apenas <b>1 opção para trocar a mão</b> durante o draft. Use com sabedoria.':'Troca de mão já usada. Agora é conviver com as escolhas.'}const count=filled().length;const capRound=!state.captainPicked&&count===0;$('boxScore').textContent=`${count}/11`;$('streamBtn').disabled=!isComplete();$('playBtn').disabled=!isComplete();$('rollBtn').disabled=isComplete()||state.rolling||state.candidates.length>0;$('rerollBtn').disabled=capRound||state.rerolls<=0||state.rolling||!state.candidates.length;$('drawLabel').textContent=isComplete()?'Equipe completa':(capRound?'Escolha do capitão':'Rodada do draft');$('drawPosition').textContent=isComplete()?'11/11':(capRound?'CAP':`${roundNumber()}/11`);$('drawDecade').textContent=isComplete()?'OK':(capRound?'5 opções 90+':'5 cartas');if(!state.rolling){$('rollMain').textContent=isComplete()?'Jogar':(state.candidates.length?'Escolha':'Role');$('rollSub').textContent=isComplete()?'libertadores':(state.candidates.length?(capRound?'escolha o capitão, sem reroll':'uma carta, as outras somem'):(capRound?'cinco líderes possíveis, todos 90+':'cinco cartas, uma escolha'))}const miss=emptySlots().map(s=>POS_LABEL[s.pos]).join(' · ');$('statusText').textContent=isComplete()?'Equipe completa · pronta para a América':(capRound?'Primeira escolha: defina o capitão da Besta':`${state.formationName} · faltam ${miss||'—'}`)}
function renderNeedTags(){const box=$('needTags');box.innerHTML=state.slots.map(s=>`<span class="${s.player?'done':''}">${POS_LABEL[s.pos]}</span>`).join('')}
function coordsFor(formation){const p={};function add(i,x,y){p[i]=[x,y]}if(formation==='4-3-3')[[50,90],[84,77],[61,81],[39,81],[16,77],[50,60],[40,44],[60,44],[82,29],[50,18],[18,29]].forEach((c,i)=>add(i,...c));else if(formation==='4-4-2')[[50,90],[84,77],[61,81],[39,81],[16,77],[39,59],[61,59],[32,40],[68,40],[38,19],[62,19]].forEach((c,i)=>add(i,...c));else if(formation==='4-2-3-1')[[50,90],[84,77],[61,81],[39,81],[16,77],[40,60],[60,60],[50,42],[82,30],[18,30],[50,18]].forEach((c,i)=>add(i,...c));else if(formation==='3-5-2')[[50,90],[68,79],[50,82],[32,79],[42,60],[58,60],[84,44],[16,44],[50,37],[38,19],[62,19]].forEach((c,i)=>add(i,...c));else if(formation==='4-2-4')[[50,90],[84,77],[61,81],[39,81],[16,77],[40,58],[60,58],[81,30],[19,30],[38,19],[62,19]].forEach((c,i)=>add(i,...c));else [[50,90],[84,77],[61,81],[39,81],[16,77],[40,60],[60,60],[84,43],[16,43],[50,37],[50,18]].forEach((c,i)=>add(i,...c));return p}
function renderPitch(){
  document.querySelectorAll('.slot').forEach(e=>e.remove());
  const coords=coordsFor(state.formationName);
  state.slots.forEach((s,i)=>{
    const el=document.createElement('div');
    const off=s.player&&s.player.penalty>0;
    let dropClass='';
    let fit=null;
    if(!s.player&&state.selectedCandidate){
      fit=fitFor(state.selectedCandidate,s.pos);
      if(fit.allowed) dropClass=fit.penalty===0?' can-drop':' drop-bad';
    }
    el.className='slot '+(s.player?'filled ':'open ')+(off?'badfit ':'')+dropClass+(state.movingSlot===i?' selected-move ':'');
    el.style.left=coords[i][0]+'%';
    el.style.top=coords[i][1]+'%';
    el.dataset.idx=i;
    el.draggable=!!s.player;
    if(s.player){
      el.title=`${s.player.name} · ${allPos(s.player)} · ${s.player.decade} · escalado em ${POS_LABEL[s.pos]}${s.player.penalty?` · penalidade -${Math.round(s.player.penalty*100)}%`:''}`;
      el.innerHTML=`<div><div class="slot-name">${esc(s.player.name)}</div><div class="slot-ovr">${s.player.adjusted}</div></div>`;
    }else if(fit&&fit.allowed){
      const pct=fit.penalty===0?'100%':`-${Math.round(fit.penalty*100)}%`;
      el.title=`${state.selectedCandidate.name} em ${POS_LABEL[s.pos]}: overall ${fit.adjusted}${fit.penalty?` · penalidade ${pct}`:' · posição natural'}`;
      el.innerHTML=`<div><div class="slot-open-pos">${POS_LABEL[s.pos]}</div><span class="fit-adjusted">${pct} · ${fit.adjusted}</span></div>`;
    }else{
      el.innerHTML=`<div class="slot-open-pos">${POS_LABEL[s.pos]}</div>`;
    }
    el.addEventListener('click',()=>{
      if(state.selectedCandidate&&!s.player)return placeCandidate(state.selectedCandidate.id,i);
      if(state.movingSlot!==null)return moveSlot(state.movingSlot,i);
      if(s.player){state.movingSlot=i;state.selectedCandidate=null;renderAll();toast(`${s.player.name}: escolha nova posição.`)}
    });
    el.addEventListener('dragstart',ev=>{if(s.player){ev.dataTransfer.setData('text/plain','slot:'+i)}});
    el.addEventListener('dragover',ev=>{ev.preventDefault();el.classList.add('drop-ok')});
    el.addEventListener('dragleave',()=>el.classList.remove('drop-ok'));
    el.addEventListener('drop',ev=>{
      ev.preventDefault();el.classList.remove('drop-ok');
      const data=ev.dataTransfer.getData('text/plain');
      if(data.startsWith('candidate:'))placeCandidate(Number(data.split(':')[1]),i);
      if(data.startsWith('slot:'))moveSlot(Number(data.split(':')[1]),i);
    });
    $('pitch').appendChild(el);
  });
}
function renderOptions(){const box=$('options');if(state.rolling){box.innerHTML='<div class="player-option"><div class="num">?</div><div><div class="name">Sorteando mão...</div><div class="meta">as cartas estão girando</div></div><div class="ovr">—</div></div>';return}if(!state.candidates.length){box.innerHTML='<div class="player-option"><div class="num">#</div><div><div class="name">Aguardando sorteio</div><div class="meta">cinco cartas aparecem, você escolhe uma</div></div><div class="ovr">—</div></div>';return}box.innerHTML=state.candidates.map((p,i)=>{const selected=state.selectedCandidate&&state.selectedCandidate.id===p.id;const pen=p.bestPenalty?` · melhor encaixe -${Math.round(p.bestPenalty*100)}%`:'';return `<div class="player-option ${rarityClass(p)} ${selected?'selected':''}" draggable="true" data-id="${p.id}" onclick="chooseCandidate(${p.id})"><div class="num">#${i+1}</div><div><div class="name">${esc(p.name)} <span class="micro">${esc(p.decade)}</span></div><div class="meta">posições ${esc(allPos(p))} · ${esc(p.rarity)} · ${esc(p.offerTag)}</div>${traitChipsHtml(p)}<span class="tagline2">Resolve melhor: ${POS_LABEL[p.bestPos]} ${pen}</span><span class="option-impact">Impacto: OVR ajustado ${p.bestAdjusted} · encaixe ${Math.round((1-(p.bestPenalty||0))*100)}/100</span></div><div class="ovr"><small>OVR</small>${p.rating}</div></div>`}).join('');box.querySelectorAll('.player-option').forEach(el=>{el.addEventListener('dragstart',ev=>{ev.dataTransfer.setData('text/plain','candidate:'+el.dataset.id);chooseCandidate(Number(el.dataset.id))})})}
function renderBox(){const vals=teamStats();$('overall').textContent=vals.overall?Math.round(vals.overall):'—';$('atkMeter').style.width=clamp((vals.attack-55)/44*100,0,100)+'%';$('defMeter').style.width=clamp((vals.defense-55)/44*100,0,100)+'%';$('boxList').innerHTML=state.slots.map(s=>`<div class="box-row"><div class="pos">${POS_LABEL[s.pos]}</div><div class="name">${s.player?`${esc(s.player.name)}${s.player.captain?'<span class="captain-badge">CAP</span>':''}<span class="allpos">${esc(allPos(s.player))} · ${esc(s.player.decade)}${s.player.penalty?` · -${Math.round(s.player.penalty*100)}%`:''}<br>${esc(traitText(s.player))}</span>`:'—'}</div><div class="ovr">${s.player?s.player.adjusted:'—'}</div></div>`).join('');let warning='';if(filled().some(s=>s.pos==='G'&&s.player&&s.player.penalty>=.7))warning='Sem goleiro natural. A defesa vai sofrer muito.';else if(vals.shapePenalty<=-4)warning='Time desequilibrado. Muito talento, pouco encaixe.';const profile=vals.overall?teamProfileHtml(vals):'';$('shapeWarning').innerHTML=(warning?`<div class="shape-warning">${warning}</div>`:'')+profile}
function chemistryStats(fs){const counts={};fs.forEach(s=>{const d=s.player&&s.player.decade?s.player.decade:'Sem década';counts[d]=(counts[d]||0)+1});let bestCount=0,bestDecade='—';Object.entries(counts).forEach(([d,n])=>{if(n>bestCount){bestCount=n;bestDecade=d}});let chemistry=bestCount>=5?100:bestCount===4?95:bestCount===3?90:bestCount===2?85:bestCount===1?80:0;return {chemistry,bestCount,bestDecade}}
function teamStats(){
  const fs=filled();
  if(!fs.length)return {overall:0,attack:0,defense:0,mid:0,fit:0,chemistry:0,bestDecade:'—',bestCount:0,shapePenalty:0,avgPenalty:0,stars:0,identity:teamTraitIdentity([])};
  let attack=avg(fs.filter(s=>groupOf(s.pos)==='att').map(s=>s.player.adjusted));
  let defense=avg(fs.filter(s=>groupOf(s.pos)==='def'||s.pos==='G').map(s=>s.player.adjusted));
  let mid=avg(fs.filter(s=>groupOf(s.pos)==='mid').map(s=>s.player.adjusted));
  let base=avg(fs.map(s=>s.player.adjusted));
  let avgPenalty=avg(fs.map(s=>s.player.penalty||0));
  let impro=fs.reduce((a,s)=>a+(s.player.penalty? s.player.penalty*5:0),0);
  let stars=fs.filter(s=>s.player.rating>=95).length;
  let bonus=(stars>=4?3:stars>=3?2:stars>=2?1:0);
  let counts={def:fs.filter(s=>['LD','ZG','LE'].includes(s.pos)&&s.player.penalty<=.2).length,mid:fs.filter(s=>groupOf(s.pos)==='mid'&&s.player.penalty<=.2).length,att:fs.filter(s=>groupOf(s.pos)==='att'&&s.player.penalty<=.2).length,gk:fs.filter(s=>s.pos==='G'&&s.player.penalty===0).length};
  let shapePenalty=0;if(!counts.gk)shapePenalty-=8;if(counts.def<3)shapePenalty-=4;if(counts.mid<2)shapePenalty-=3;if(counts.att<1)shapePenalty-=2;
  const identity=teamTraitIdentity(fs);
  const traitBalance=(identity.diversity-70)*.035;
  let overall=clamp(base-impro+bonus+shapePenalty+traitBalance,45,99);
  attack=attack||overall;defense=defense||overall;mid=mid||overall;
  let spread=Math.max(attack,defense,mid)-Math.min(attack,defense,mid);
  const chem=chemistryStats(fs);
  let fit=clamp(100-avgPenalty*170+shapePenalty*1.8-(spread>12?(spread-12)*.75:0),35,100);
  return {overall,attack,defense,mid,fit,chemistry:chem.chemistry,bestDecade:chem.bestDecade,bestCount:chem.bestCount,shapePenalty,avgPenalty,stars,counts,spread,identity}
}
function teamProfile(vals){const o=Math.round(vals.overall||0),a=Math.round(vals.attack||0),m=Math.round(vals.mid||0),d=Math.round(vals.defense||0),f=Math.round(vals.fit||0),c=Math.round(vals.chemistry||0);let title='Em formação',chance='—',verdict='Monte os 11 para avaliar a campanha.';if(o>0&&o<86){title='Sobrevivente';chance='0–2%';verdict='Pode passar do grupo, mas título seria milagre.'}else if(o<90){title='Franco-atirador';chance='2–5%';verdict='Boa campanha possível, mas precisa de sorte e chave amiga.'}else if(o<93){title='Competitivo';chance='5–10%';verdict='Pode ser campeão, mas o mata-mata vai cobrar cada detalhe.'}else if(o<96){title='Candidato';chance='10–18%';verdict='Time com cara de Libertadores. Forte, mas ainda vulnerável.'}else if(o>0){title='Besta histórica';chance='20–30%';verdict='Favorito real, sem virar automático. A América ainda pode aprontar.'}let risk='';if(o>0){const low=Math.min(a,m,d);if(f<70)risk='Encaixe baixo: muito talento, pouca ordem.';else if(d<84)risk='Risco: defesa vulnerável.';else if(m<84)risk='Risco: meio-campo sem controle.';else if(a<84)risk='Risco: falta poder de decisão.';else if(Math.max(a,m,d)-low>12)risk='Risco: time desequilibrado.';else risk='Encaixe: equilibrado.';if(c>=95)risk+=' Entrosamento histórico pela concentração de jogadores da mesma década.'}return {title,chance,verdict,risk,overall:o,attack:a,mid:m,defense:d,fit:f,chemistry:c,bestDecade:vals.bestDecade,bestCount:vals.bestCount}}
function teamProfileHtml(vals){const p=teamProfile(vals);if(!p.overall)return '';const chemLabel=p.bestCount>=2?`${p.chemistry}<small style="display:block;font-size:9px;color:var(--blue700)">${esc(p.bestCount+'x '+p.bestDecade)}</small>`:String(p.chemistry);return `<div class="team-profile-card"><div class="profile-kicker">Raio-X da Besta</div><div class="profile-title">${esc(p.title)}</div><div class="profile-grid"><div class="profile-stat"><span>Título</span><b>${esc(p.chance)}</b></div><div class="profile-stat"><span>Ataque</span><b>${p.attack}</b></div><div class="profile-stat"><span>Meio</span><b>${p.mid}</b></div><div class="profile-stat"><span>Defesa</span><b>${p.defense}</b></div><div class="profile-stat"><span>Encaixe</span><b>${p.fit}</b></div><div class="profile-stat"><span>Entrosamento</span><b>${chemLabel}</b></div></div><p class="profile-text">${esc(p.verdict)} ${esc(p.risk)}</p><div class="profile-kicker trait-kicker">Identidade da Besta</div>${identityMiniHtml(vals.identity)}</div>`}
function toast(msg){const t=$('toast');t.textContent=msg;t.style.display='block';clearTimeout(toast._t);toast._t=setTimeout(()=>t.style.display='none',2300)}
function opponentLabel(o){return `${o.club} ${o.year}`}function worldOpponent(){return WORLD_CHALLENGE||DEFAULT_WORLD_CHALLENGE}function opponentHero(o){const names=String(o.players||'').split(';').map(x=>x.trim()).filter(Boolean);return sample(names)||opponentLabel(o)}function oppPool(min,max){let arr=OPPONENTS.filter(o=>!norm(o.club).includes('cruzeiro')&&o.rating>=min&&o.rating<=max);return arr.length?arr:OPPONENTS.filter(o=>!norm(o.club).includes('cruzeiro'))}function pickOpp(min,max,used){let arr=shuffle(oppPool(min,max).filter(o=>!used.has(o.id)));let o=arr[0]||shuffle(OPPONENTS.filter(o=>!norm(o.club).includes('cruzeiro')&&!used.has(o.id)))[0];used.add(o.id);return o}
function bestPlayer(){return [...filled()].sort((a,b)=>b.player.rating-a.player.rating)[0]?.player||{name:'LaBestia',rating:90}}function scorer(){let arr=filled().filter(s=>['ATA','PE','PD','MEI','MD','ME'].includes(s.pos)&&s.player.adjusted>=70).map(s=>s.player);if(!arr.length)arr=filled().map(s=>s.player);return weighted(arr,p=>{const tr=playerTraits(p);let w=Math.max(1,(p.adjusted||p.rating)-60)+(p.rating>=95?8:0);if(tr.includes('Finalização'))w*=1.45;if(tr.includes('Presença de área'))w*=1.25;if(tr.includes('Bola Aérea'))w*=1.12;if(tr.includes('Drible'))w*=1.10;return w}).name}
function shareGame(){const data={title:'LaBestia',text:'Monte a Besta e tente levar o Cruzeiro ao tri da Libertadores.',url:location.href};if(navigator.share){navigator.share(data).catch(()=>{})}else if(navigator.clipboard){navigator.clipboard.writeText(location.href).then(()=>toast('Link copiado!')).catch(()=>toast('Copie o link da barra do navegador.'))}else{toast('Copie o link da barra do navegador.')}}
function openTournament(){if(!isComplete()){toast('Complete os 11 jogadores primeiro.');return}$('tournamentModal').classList.add('open');if(!state.tournament)return renderModeChoice();renderCampaign()}function closeTournament(){$('tournamentModal').classList.remove('open')}
function renderModeChoice(){const vals=teamStats();const profile=teamProfileHtml(vals);$('modalSub').textContent='Escolha como a Libertadores será jogada';$('tournamentContent').innerHTML=`<div class="final-banner">Escolha o modo da campanha</div>${profile}<div class="mode-choice"><div class="mode-card"><div><div class="tagline">rápido · placar vivo · sem pausas</div><h3>Modo Clássico</h3><p>O placar se movimenta dos 0 aos 90 minutos. Os autores dos gols aparecem no momento em que a rede balança.</p><ul><li>mais direto;</li><li>ideal para várias tentativas;</li><li>A América Cobra explica o resultado depois do jogo.</li></ul></div><button class="btn-primary" onclick="startTournamentMode('classic')">Jogar clássico</button></div><div class="mode-card"><div><div class="tagline">tático · banco · intervalo</div><h3>Modo Elifoot</h3><p>Antes da campanha, escolha 7 suplentes para o banco. No intervalo, você pode acionar até 3 jogadores para mudar o segundo tempo.</p><ul><li>mais controle durante o jogo;</li><li>decisões táticas no intervalo;</li><li>banco pode mudar mata-mata.</li></ul></div><button class="btn-primary" onclick="startTournamentMode('elifoot')">Jogar Elifoot</button></div></div><div class="panel" style="margin-top:18px"><h3>Ranking local</h3>${rankingHtml(3)}</div>`}
function startTournamentMode(mode){createTournament(mode);if(mode==='elifoot')setupBenchDraft();renderCampaign()}
function createTournament(mode='classic'){const used=new Set();const group=[pickOpp(80,85,used),pickOpp(84,87,used),pickOpp(86,89,used)];const schedule=[{round:1,userHome:true,opp:group[0],otherHome:group[1],otherAway:group[2]},{round:2,userHome:false,opp:group[1],otherHome:group[2],otherAway:group[0]},{round:3,userHome:true,opp:group[2],otherHome:group[0],otherAway:group[1]},{round:4,userHome:false,opp:group[0],otherHome:group[2],otherAway:group[1]},{round:5,userHome:true,opp:group[1],otherHome:group[0],otherAway:group[2]},{round:6,userHome:false,opp:group[2],otherHome:group[1],otherAway:group[0]}];const table={LaBestia:newRow('LaBestia')};group.forEach(o=>table[opponentLabel(o)]=newRow(opponentLabel(o)));const stats=teamStats();state.tournament={mode,stage:'group',stats,profile:teamProfile(stats),group,schedule,roundIndex:0,table,history:[],record:{v:0,e:0,d:0},used,match:null,ko:null,outcome:'',goalsFor:0,goalsAgainst:0,matches:[],scorers:{},penaltyWins:0,completedSaved:false,morale:80,moraleLog:['Moral inicial da Besta: 80.'],currentMoraleEvent:null,market:null,transfersMade:0,bench:[],benchDraft:null,benchUsedTotal:0,elifootSpeed:'1x',squadReturnStage:null,squadManager:null,finalVenue:null,world:null,libertadoresChampion:false};saveProgress()}
function newRow(name){return {name,j:0,v:0,e:0,d:0,gp:0,gc:0,sg:0,pts:0}}function applyResult(table,home,away,hg,ag){for(const [n,gf,ga,isHome] of [[home,hg,ag,true],[away,ag,hg,false]]){const r=table[n]||(table[n]=newRow(n));r.j++;r.gp+=gf;r.gc+=ga;r.sg=r.gp-r.gc;if(gf>ga){r.v++;r.pts+=3}else if(gf===ga){r.e++;r.pts++}else r.d++}}function tableSorted(t){return Object.values(t).sort((a,b)=>b.pts-a.pts||b.sg-a.sg||b.gp-a.gp)}
function renderCampaign(){const t=state.tournament;$('modalSub').textContent=t.mode==='classic'?'Modo Clássico · placar em movimento':'Modo Elifoot · banco e tática';if(t.stage==='over')return renderOver();if(t.stage==='penalties')return renderPenaltyScreen();if(t.stage==='bench')return renderBenchDraftScreen();if(t.stage==='market')return renderMarketScreen();if(t.stage==='squad')return renderSquadManagerScreen();if(t.stage==='world_ready')return renderWorldReadyScreen();if(t.match)return t.mode==='classic'?renderClassicMatch():renderElifootMatch();if(t.stage==='world')return renderWorldScreen();if(t.stage==='group')return renderGroupScreen();if(t.stage==='group_done')return renderGroupCompleteScreen();return renderKoScreen()}function modeName(m){return m==='classic'?'Clássico':'Elifoot'}function historyHtml(h){return `<div class="history">${h.length?h.map(x=>`<div class="history-item">${esc(x)}</div>`).join(''):'<div class="history-item">A campanha ainda vai começar.</div>'}</div>`}function tableHtml(table){return `<table class="table"><thead><tr><th>Time</th><th>Pts</th><th>J</th><th>V</th><th>E</th><th>D</th><th>SG</th></tr></thead><tbody>${tableSorted(table).map(r=>`<tr><td>${esc(r.name)}</td><td>${r.pts}</td><td>${r.j}</td><td>${r.v}</td><td>${r.e}</td><td>${r.d}</td><td>${r.sg}</td></tr>`).join('')}</tbody></table>`}
function renderGroupCompleteScreen(){const t=state.tournament;const pos=tableSorted(t.table).findIndex(r=>r.name==='LaBestia')+1;$('tournamentContent').innerHTML=`<div class="campaign"><div class="panel"><div class="group-complete-hero"><h3>Classificação confirmada</h3><p>LaBestia terminou a fase de grupos em ${pos}º lugar. Confira a tabela final antes de encarar o mata-mata.</p></div>${tableHtml(t.table)}<div class="group-complete-note"><b>Janela de transferências</b><br>Antes das oitavas, a diretoria pode liberar reforços. A América cobra elenco, não só onze titulares.</div><div class="toolbar"><button class="btn-primary" onclick="advanceToKnockout()">Abrir janela pré-oitavas</button><button onclick="closeTournament()">Fechar</button></div></div><div class="panel"><h3>Histórico da fase de grupos</h3>${historyHtml(t.history)}<h3 style="margin-top:18px">Moral</h3>${moralePanelHtml(t)}</div></div>`}
function advanceToKnockout(){openTransferMarket();renderCampaign()}

function completeMarket(){startKnockout();saveProgress();renderCampaign()}

function benchTakenIds(){const t=state.tournament;return new Set((t&&t.bench?t.bench:[]).map(p=>p.id))}
function benchPoolForGroup(group,exclude=new Set()){
  const names=currentSquadNames(true);
  let arr=PLAYERS.filter(p=>!names.has(norm(p.name))&&!exclude.has(p.id));
  if(group==='G')arr=arr.filter(p=>[...(p.positions||[]),p.primary].includes('G'));
  else arr=arr.filter(p=>[...(p.positions||[]),p.primary].some(pos=>groupOf(pos)===group));
  if(!arr.length)arr=PLAYERS.filter(p=>!names.has(norm(p.name))&&!exclude.has(p.id));
  return arr;
}
function generateBenchOptions(){const t=state.tournament;if(!t)return [];const bd=t.benchDraft||{round:0};const target=BENCH_TARGETS[Math.min(bd.round||0,BENCH_TARGETS.length-1)]||'att';const ex=new Set();const opts=[];while(opts.length<3){const pool=benchPoolForGroup(target,ex);if(!pool.length)break;const p=weighted(pool,x=>baseWeight(x)*Math.max(1,x.rating-70)*(x.rating>=90?1.35:1));if(!p)break;ex.add(p.id);opts.push({...p,benchTarget:target});}return opts;}
function setupBenchDraft(){const t=state.tournament;if(!t)return;t.stage='bench';t.bench=[];t.benchDraft={round:0,options:generateBenchOptions()};t.history.unshift('Elifoot: comissão abriu a escolha dos 7 suplentes.');saveProgress()}
function renderBenchDraftScreen(){const t=state.tournament,bd=t.benchDraft||{round:0,options:[]};const target=BENCH_TARGETS[Math.min(bd.round||0,BENCH_TARGETS.length-1)]||'att';$('modalSub').textContent='Modo Elifoot · escolha do banco';if((t.bench||[]).length>=7){return renderBenchCompleteScreen()}$('tournamentContent').innerHTML=`<div class="final-banner">Monte o banco da Besta</div><div class="campaign"><div class="panel"><h3>Suplente ${(t.bench||[]).length+1}/7 · ${esc(benchGroupLabel(target))}</h3><p class="small">No Modo Elifoot, o banco pode ser acionado no intervalo. Escolha um dos três nomes para compor os 7 suplentes.</p><div class="market-options bench-options">${(bd.options||[]).map(p=>benchOptionHtml(p)).join('')}</div><div class="toolbar"><button onclick="autoFillBench()">Completar automático</button></div></div><div class="panel"><h3>Banco atual</h3>${benchListHtml(t.bench)}<h3 style="margin-top:18px">Titulares</h3>${marketSquadHtml(false)}</div></div>`}
function benchOptionHtml(p){return `<div class="market-option bench-option"><div><b>${esc(p.name)}</b><span>${esc(p.decade)} · ${esc(allPos(p))} · OVR ${p.rating}<br>${esc(traitText(p))}</span></div><button class="btn-primary" onclick="chooseBenchPlayer(${p.id})">Levar para o banco</button></div>`}
function chooseBenchPlayer(id){const t=state.tournament,bd=t.benchDraft;if(!t||!bd)return;const p=(bd.options||[]).find(x=>x.id===id);if(!p)return;t.bench=t.bench||[];t.bench.push({...p});bd.round=(bd.round||0)+1;if(t.bench.length>=7){t.history.unshift('Elifoot: banco fechado com 7 suplentes.');saveProgress();return renderBenchCompleteScreen()}bd.options=generateBenchOptions();saveProgress();renderCampaign()}
function autoFillBench(){const t=state.tournament;if(!t)return;t.bench=t.bench||[];t.benchDraft=t.benchDraft||{round:t.bench.length,options:[]};while(t.bench.length<7){let opts=t.benchDraft.options&&t.benchDraft.options.length?t.benchDraft.options:generateBenchOptions();if(!opts.length)break;const p=opts[0];t.bench.push({...p});t.benchDraft.round=(t.benchDraft.round||0)+1;t.benchDraft.options=generateBenchOptions();}t.history.unshift('Elifoot: banco completado automaticamente.');saveProgress();renderBenchCompleteScreen()}
function renderBenchCompleteScreen(){const t=state.tournament;$('tournamentContent').innerHTML=`<div class="final-banner">Banco fechado</div><div class="campaign"><div class="panel"><h3>7 suplentes escolhidos</h3><p class="small">No intervalo dos jogos do Modo Elifoot, você poderá acionar até 3 jogadores do banco para tentar mudar o segundo tempo.</p>${benchListHtml(t.bench)}<div class="toolbar"><button class="btn-primary" onclick="finishBenchDraft()">Começar Libertadores</button></div></div><div class="panel"><h3>Raio-X da Besta</h3>${teamProfileHtml(t.stats)}</div></div>`}
function finishBenchDraft(){const t=state.tournament;if(!t)return;t.stage='group';t.benchDraft=null;t.history.unshift('Elifoot: LaBestia iniciou a campanha com banco completo.');saveProgress();renderCampaign()}
function benchListHtml(list=[]){if(!list.length)return '<div class="history-item">Banco ainda vazio.</div>';return `<div class="market-squad bench-list">${list.map((p,i)=>`<div class="market-row"><div><b>#${i+1} · ${esc(p.name)}</b><span>${esc(p.decade)} · ${esc(allPos(p))} · OVR ${p.rating}</span></div></div>`).join('')}</div>`}
function benchActionHtml(m){const t=state.tournament;if(!t||t.mode!=='elifoot'||!t.bench||!t.bench.length||m.done)return '';const used=new Set(m.usedBenchIds||[]);const limit=3;const remaining=limit-(m.substitutions||0);if(m.phaseState!=='half')return `<div class="panel bench-panel"><h3>Banco Elifoot</h3>${benchListHtml(t.bench)}</div>`;if(remaining<=0)return `<div class="panel bench-panel"><h3>Banco Elifoot</h3><p class="small">As 3 intervenções do intervalo já foram usadas.</p>${benchListHtml(t.bench)}</div>`;return `<div class="panel bench-panel"><h3>Banco Elifoot · ${remaining} mudança${remaining>1?'s':''}</h3><p class="small">Acione suplentes para dar impulso ao segundo tempo. Atacantes aumentam pressão, meias dão controle e defensores fecham a casa.</p><div class="bench-action-grid">${t.bench.map(p=>`<button class="btn-soft" ${used.has(p.id)?'disabled':''} onclick="useBenchPlayer(${p.id})">${esc(p.name)}<br><small>${esc(allPos(p))} · ${p.rating}</small></button>`).join('')}</div></div>`}
function useBenchPlayer(id){const t=state.tournament,m=t&&t.match;if(!m||m.phaseState!=='half')return;if((m.substitutions||0)>=3){toast('Limite de 3 intervenções no intervalo.');return}m.usedBenchIds=m.usedBenchIds||[];if(m.usedBenchIds.includes(id)){toast('Este suplente já entrou.');return}const p=(t.bench||[]).find(x=>x.id===id);if(!p)return;const positions=[...(p.positions||[]),p.primary].filter(Boolean);const groups=[...new Set(positions.map(groupOf))];m.subBoost=m.subBoost||{atk:0,def:0,tempo:0,late:0};const quality=clamp((p.rating-80)/3,1,6);if(groups.includes('att')){m.subBoost.atk+=quality;m.subBoost.tempo+=.04;m.subBoost.late+=.025}else if(groups.includes('mid')){m.subBoost.atk+=quality*.55;m.subBoost.def+=quality*.55;m.subBoost.tempo+=.025}else if(groups.includes('def')||groups.includes('gk')){m.subBoost.def+=quality;m.subBoost.tempo-=.015}m.substitutions=(m.substitutions||0)+1;m.usedBenchIds.push(id);t.benchUsedTotal=(t.benchUsedTotal||0)+1;m.events.unshift({min:46,type:'chance',side:'user',text:`${p.name} saiu do banco para mudar o jogo.`});toast(`${p.name} entrou. O segundo tempo mudou.`);saveProgress();renderElifootMatch()}
function openTransferMarket(){const t=state.tournament;if(t.market&&t.market.closed)return completeMarket();const limit=rnd(1,3);t.stage='market';t.market={limit,used:0,accepted:false,activeSlot:null,options:[],closed:false,decidedSlots:[]};t.history.unshift(`Mercado: a diretoria liberou ${limit} contratação${limit>1?'ões':''} antes das oitavas.`);saveProgress()}

function openSquadManager(){
  const t=state.tournament;
  if(!t||t.mode!=='elifoot'){toast('Gestão de equipa disponível no Modo Elifoot.');return}
  t.squadReturnStage=t.stage;
  t.stage='squad';
  t.squadManager={activeSlot:null};
  saveProgress();
  renderCampaign();
}
function closeSquadManager(){
  const t=state.tournament;if(!t)return;
  t.stage=t.squadReturnStage||'group';
  t.squadReturnStage=null;t.squadManager=null;
  t.stats=teamStats();
  saveProgress();renderCampaign();
}
function cleanBenchPlayer(p){const q={...p};delete q.assigned;delete q.penalty;delete q.adjusted;delete q.fitLabel;delete q.finalTwist;delete q.finalDelta;return q}
function squadStarterRows(){
  return `<div class="squad-grid">${state.slots.map((s,i)=>{const p=s.player;return `<div class="squad-row"><div><b>${esc(POS_LABEL[s.pos])} · ${p?esc(p.name):'—'}</b><span>${p?`${esc(allPos(p))} · ${esc(p.decade)} · OVR ${p.rating} · ajuste ${p.adjusted}<br>${esc(traitText(p))}`:'posição vazia'}</span></div><button ${p?'':'disabled'} onclick="selectSquadSlot(${i})">Escolher reserva</button></div>`}).join('')}</div>`
}
function squadBenchRows(){const t=state.tournament,list=t&&t.bench?t.bench:[];if(!list.length)return '<div class="history-item">Sem reservas disponíveis.</div>';return `<div class="squad-grid">${list.map((p,i)=>`<div class="squad-row"><div><b>#${i+1} · ${esc(p.name)}</b><span>${esc(allPos(p))} · ${esc(p.decade)} · OVR ${p.rating}<br>${esc(traitText(p))}</span></div></div>`).join('')}</div>`}
function selectSquadSlot(idx){const t=state.tournament;if(!t)return;t.squadManager=t.squadManager||{};t.squadManager.activeSlot=idx;renderCampaign()}
function cancelSquadSlot(){const t=state.tournament;if(!t)return;t.squadManager=t.squadManager||{};t.squadManager.activeSlot=null;renderCampaign()}
function squadCandidateRows(slotIdx){
  const t=state.tournament,slot=state.slots[slotIdx],bench=t&&t.bench?t.bench:[];
  const rows=bench.map((p,i)=>({p,i,fit:fitFor(p,slot.pos)})).filter(x=>x.fit.allowed).sort((a,b)=>a.fit.penalty-b.fit.penalty||b.fit.adjusted-a.fit.adjusted);
  if(!rows.length)return '<div class="history-item">Nenhum reserva pode entrar nesta posição.</div>';
  return `<div class="squad-grid">${rows.map(x=>`<div class="squad-row ${x.fit.penalty===0?'best-fit':''}"><div><b>${esc(x.p.name)}</b><span>${esc(allPos(x.p))} · ${esc(x.p.decade)} · OVR ${x.p.rating} · entra como ${x.fit.adjusted} (${esc(x.fit.label)})<br>${esc(traitText(x.p))}</span></div><button class="btn-primary" onclick="swapBenchWithStarter(${slotIdx},${x.i})">Colocar</button></div>`).join('')}</div>`
}
function swapBenchWithStarter(slotIdx,benchIdx){
  const t=state.tournament,slot=state.slots[slotIdx];if(!t||!slot||!t.bench||!t.bench[benchIdx])return;
  const incoming=t.bench[benchIdx],outgoing=slot.player;if(!outgoing)return;
  const fit=fitFor(incoming,slot.pos);if(!fit.allowed){toast('Reserva não pode atuar nesta posição.');return}
  const captain=!!outgoing.captain;
  slot.player={...incoming,assigned:slot.pos,penalty:fit.penalty,adjusted:fit.adjusted,fitLabel:fit.label,captain};
  t.bench[benchIdx]=cleanBenchPlayer(outgoing);
  t.stats=teamStats();
  t.history.unshift(`Elifoot: ${incoming.name} virou titular no lugar de ${outgoing.name}.`);
  t.squadManager={activeSlot:null};
  saveProgress();
  toast(`${incoming.name} agora é titular.`);
  renderCampaign();
}
function renderSquadManagerScreen(){
  const t=state.tournament,sm=t.squadManager||{};$('modalSub').textContent='Modo Elifoot · montar equipa';
  if(sm.activeSlot!==null&&sm.activeSlot!==undefined){const slot=state.slots[sm.activeSlot],p=slot.player;$('tournamentContent').innerHTML=`<div class="final-banner">Montar equipa</div><div class="campaign"><div class="panel"><h3>${esc(POS_LABEL[slot.pos])} · ${p?esc(p.name):'posição vaga'}</h3><p class="small">Escolha um reserva para virar titular. O jogador que sair vai para o banco.</p>${squadCandidateRows(sm.activeSlot)}<div class="toolbar"><button onclick="cancelSquadSlot()">Voltar</button><button class="btn-primary" onclick="closeSquadManager()">Concluir</button></div></div><div class="panel"><h3>Raio-X atualizado</h3>${teamProfileHtml(teamStats())}</div></div>`;return}
  $('tournamentContent').innerHTML=`<div class="final-banner">Montar equipa</div><div class="campaign"><div class="panel"><h3>Titulares</h3><p class="small">Troque titulares por reservas antes de iniciar a partida. O encaixe é recalculado na hora.</p>${squadStarterRows()}<div class="toolbar"><button class="btn-primary" onclick="closeSquadManager()">Concluir</button></div></div><div class="panel"><h3>Banco</h3>${squadBenchRows()}<h3 style="margin-top:18px">Raio-X</h3>${teamProfileHtml(teamStats())}</div></div>`
}

function renderMarketScreen(){const t=state.tournament,m=t.market||{limit:1,used:0,accepted:false,options:[]};$('modalSub').textContent='Janela de transferências · pré-oitavas';const remaining=m.limit-m.used;if(!m.accepted){$('tournamentContent').innerHTML=`<div class="final-banner">O mercado está aberto</div><div class="campaign"><div class="panel"><h3>Janela pré-oitavas</h3><p class="small"><b>O mercado está aberto, a diretoria te permitiu contratar ${m.limit} jogador${m.limit>1?'es':''}.</b><br>Você pode aceitar a ida ao mercado ou manter a Besta como está. Cada contratação substitui um jogador do elenco por uma de três opções da mesma posição.</p><div class="mini-cards"><div class="mini-card"><span class="micro">Moral</span><br><b>${Math.round(t.morale??80)}</b></div><div class="mini-card"><span class="micro">Força</span><br><b>${Math.round(t.stats.overall)}</b></div><div class="mini-card"><span class="micro">Encaixe</span><br><b>${Math.round(t.stats.fit||0)}</b></div></div><div class="toolbar"><button class="btn-primary" onclick="acceptMarket()">Ir ao mercado</button><button onclick="declineMarket()">Manter elenco</button></div></div><div class="panel"><h3>Elenco atual</h3>${marketSquadHtml()}</div></div>`;return}if(m.activeSlot!==null){$('tournamentContent').innerHTML=`<div class="final-banner">Proposta da diretoria</div><div class="campaign"><div class="panel"><h3>Substituição</h3>${marketActiveSlotHtml(m.activeSlot)}<p class="small">A diretoria trouxe três nomes da mesma posição. Esta proposta é fechada: escolha um reforço e siga em frente com a troca, ou prefira manter seu jogador.</p><div class="market-options">${m.options.map(p=>marketOptionHtml(p,m.activeSlot)).join('')}</div><div class="toolbar"><button onclick="keepMarketPlayer(${m.activeSlot})">Prefiro manter meu jogador</button><button onclick="finishMarket()">Encerrar janela</button></div></div><div class="panel"><h3>Raio-X atual</h3>${teamProfileHtml(t.stats)}${moralePanelHtml(t)}</div></div>`;return}$('tournamentContent').innerHTML=`<div class="final-banner">Mercado da Besta</div><div class="campaign"><div class="panel"><h3>Contratações restantes: ${remaining}</h3><p class="small">Escolha quem pode sair. Para cada jogador, a diretoria apresenta três opções fechadas da mesma posição: aceitar uma troca ou manter o titular.</p>${marketSquadHtml(true)}<div class="toolbar"><button class="btn-primary" onclick="finishMarket()">${remaining>0?'Encerrar janela':'Avançar para as oitavas'}</button></div></div><div class="panel"><h3>Raio-X após mercado</h3>${teamProfileHtml(t.stats)}${moralePanelHtml(t)}<h3 style="margin-top:18px">Movimentações</h3>${historyHtml((t.marketLog||[]).slice(0,6))}</div></div>`}
function acceptMarket(){const t=state.tournament;if(!t.market)return;t.market.accepted=true;t.history.unshift('Mercado: LaBestia aceitou buscar reforços antes das oitavas.');saveProgress();renderCampaign()}
function declineMarket(){const t=state.tournament;if(t.market){t.market.closed=true;t.history.unshift('Mercado: comissão manteve o elenco fechado para o mata-mata.')}completeMarket()}
function finishMarket(){const t=state.tournament;if(t.market){t.market.closed=true;t.history.unshift(`Mercado encerrado: ${t.market.used||0} contratação${(t.market.used||0)===1?'':'ões'} realizada${(t.market.used||0)===1?'':'s'}.`)}completeMarket()}
function marketSquadHtml(clickable=false){const m=state.tournament?.market;return `<div class="market-squad">${state.slots.map((s,i)=>{const p=s.player;if(!p)return '';const decided=!!(m&&Array.isArray(m.decidedSlots)&&m.decidedSlots.includes(i));const btn=clickable?(decided?`<button disabled>Decisão tomada</button>`:`<button class="btn-soft" onclick="prepareMarketSlot(${i})">Receber proposta</button>`):'';return `<div class="market-row"><div><b>${esc(POS_LABEL[s.pos])} · ${esc(p.name)}</b><span>${esc(allPos(p))} · ${esc(p.decade)} · OVR ${p.adjusted}<br>${esc(traitText(p))}</span></div>${btn}</div>`}).join('')}</div>`}
function marketActiveSlotHtml(i){const s=state.slots[i],p=s.player;return `<div class="market-current"><b>Sai?</b><span>${esc(POS_LABEL[s.pos])} · ${esc(p.name)} · ${esc(p.decade)} · OVR ${p.adjusted}</span></div>`}
function marketOptionHtml(p,slotIdx){const s=state.slots[slotIdx],fit=fitFor(p,s.pos);return `<div class="market-option"><div><b>${esc(p.name)}</b><span>${esc(p.decade)} · ${esc(allPos(p))} · OVR ${p.rating} → ${fit.adjusted}<br>${esc(traitText(p))}</span></div><button class="btn-primary" onclick="confirmMarketTransfer(${slotIdx},${p.id})">Seguir em frente com a troca</button></div>`}
function prepareMarketSlot(slotIdx){const t=state.tournament,m=t.market;if(!m||m.used>=m.limit){toast('A diretoria não liberou mais contratações.');return}m.decidedSlots=m.decidedSlots||[];if(m.decidedSlots.includes(slotIdx)){toast('Essa decisão de mercado já foi tomada.');return}const slot=state.slots[slotIdx];if(!slot||!slot.player)return;const names=currentSquadNames(true);let pool=PLAYERS.filter(p=>!names.has(norm(p.name))).map(p=>({p,fit:fitFor(p,slot.pos)})).filter(x=>x.fit.allowed&&x.fit.penalty===0);if(pool.length<3)pool=PLAYERS.filter(p=>!names.has(norm(p.name))).map(p=>({p,fit:fitFor(p,slot.pos)})).filter(x=>x.fit.allowed&&x.fit.penalty<=.10);if(pool.length<3)pool=PLAYERS.filter(p=>!names.has(norm(p.name))).map(p=>({p,fit:fitFor(p,slot.pos)})).filter(x=>x.fit.allowed&&x.fit.penalty<=.20);const opts=[],ex=new Set();while(opts.length<3&&pool.length){const p=weighted(pool.filter(x=>!ex.has(x.p.id)),x=>baseWeight(x.p)*(x.fit.penalty===0?3:1.5)*Math.max(1,x.p.rating-70));if(!p)break;ex.add(p.p.id);opts.push(p.p)}if(!opts.length){toast('Sem opções disponíveis para esta posição.');return}m.activeSlot=slotIdx;m.options=opts;saveProgress();renderCampaign()}
function keepMarketPlayer(slotIdx){const t=state.tournament,m=t.market;if(!m)return;m.decidedSlots=m.decidedSlots||[];if(!m.decidedSlots.includes(slotIdx))m.decidedSlots.push(slotIdx);const slot=state.slots[slotIdx];const name=slot?.player?.name||'jogador';m.activeSlot=null;m.options=[];t.marketLog=t.marketLog||[];t.marketLog.unshift(`${name} ficou. A comissão recusou a proposta da diretoria.`);t.history.unshift(`Mercado: ${name} foi mantido no elenco.`);saveProgress();renderCampaign()}
function confirmMarketTransfer(slotIdx,playerId){const t=state.tournament,m=t.market,slot=state.slots[slotIdx],p=m.options.find(x=>x.id===playerId);if(!m||!slot||!p)return;m.decidedSlots=m.decidedSlots||[];if(!m.decidedSlots.includes(slotIdx))m.decidedSlots.push(slotIdx);const old=slot.player,fit=fitFor(p,slot.pos);slot.player={...p,assigned:slot.pos,penalty:fit.penalty,adjusted:fit.adjusted,fitLabel:fit.label,captain:false};m.used++;m.activeSlot=null;m.options=[];t.transfersMade=(t.transfersMade||0)+1;t.marketLog=t.marketLog||[];t.marketLog.unshift(`${old.name} saiu, ${p.name} chegou para ${POS_LABEL[slot.pos]}.`);t.history.unshift(`Mercado: ${old.name} saiu, ${p.name} chegou para ${POS_LABEL[slot.pos]}.`);t.stats=teamStats();clearDraftCaches();saveProgress();renderAll();if(m.used>=m.limit){toast('Limite de contratações atingido.');}renderCampaign()}
function moralePanelHtml(t=state.tournament){if(!t)return '';const morale=Math.round(t.morale??80);let tag=morale>=90?'Elenco em festa':morale>=80?'Ambiente bom':morale>=70?'Atenção no vestiário':'Clima pesado';return `<div class="morale-card"><div class="morale-kicker">Moral da Besta</div><div class="morale-score">${morale}<span>/100</span></div><p>${esc(tag)}</p>${(t.moraleLog&&t.moraleLog.length)?`<small>${esc(t.moraleLog[0])}</small>`:''}</div>`}
function adjustMorale(delta,reason){const t=state.tournament;if(!t)return;const before=t.morale??80;t.morale=clamp(before+delta,0,100);t.moraleLog=t.moraleLog||[];const sign=delta>0?'+':'';t.moraleLog.unshift(`${reason} Moral ${before} → ${Math.round(t.morale)} (${sign}${delta}).`);t.history.unshift(`Moral: ${reason} ${sign}${delta}.`)}
function updateMoraleAfterMatch(userGoals,oppGoals){if(userGoals>oppGoals){const goleada=userGoals-oppGoals>=3;adjustMorale(goleada?8:5,goleada?'Vitória por goleada.':'Vitória celeste.')}else if(userGoals<oppGoals){const goleada=oppGoals-userGoals>=3;adjustMorale(goleada?-8:-5,goleada?'Derrota por goleada.':'Derrota continental.')}}
function triggerRandomMoraleEvent(){const t=state.tournament;if(!t||Math.random()>=.10){t.currentMoraleEvent=null;return null}const starters=filled().map(s=>s.player).filter(Boolean);const player=(sample(starters)||bestPlayer()).name;const good=[{d:5,msg:'Pedrinho mandou 5kg de picanha para geral!'},{d:5,msg:'O motorista do Sorín avisou: vem reforço graúdo por aí...'},{d:5,msg:`${player} fez um curso intensivo de pandeiro e fez a festa.`}];const bad=[{d:-5,msg:'Thiago Neves mandou um vídeo (des)motivacional.'},{d:-5,msg:`Uma dancinha do ${player} no TikTok repercutiu mal.`},{d:-5,msg:'Pedrinho deu uma entrevista confusa e os jogadores não gostaram.'}];const ev=sample(Math.random()<.5?good:bad);adjustMorale(ev.d,ev.msg);t.currentMoraleEvent=ev;return ev}
function moraleEventHtml(){const ev=state.tournament&&state.tournament.currentMoraleEvent;if(!ev)return '';return `<div class="morale-event ${ev.d>0?'good':'bad'}"><b>Evento de vestiário</b><br>${esc(ev.msg)} <span>${ev.d>0?'+':'-'}5 moral</span></div>`}
function renderGroupScreen(){const t=state.tournament,next=t.schedule[t.roundIndex];let home=next.userHome?'LaBestia':opponentLabel(next.opp),away=next.userHome?opponentLabel(next.opp):'LaBestia';const dossier=matchDossierHtml({opp:next.opp,home:next.userHome,neutral:false},'balanced');$('tournamentContent').innerHTML=`<div class="campaign"><div class="panel"><h3>Grupo</h3>${tableHtml(t.table)}<div class="phase">Histórico</div>${historyHtml(t.history)}</div><div class="panel"><div class="next-card"><div class="versus">${esc(home)} x ${esc(away)}</div><div class="meta">Rodada ${next.round} · ${next.userHome?'casa':'fora'} · rival nota ${next.opp.rating} · ${modeName(t.mode)}</div></div>${dossier}<div class="mini-cards"><div class="mini-card"><span class="micro">Força</span><br><b>${Math.round(t.stats.overall)}</b></div><div class="mini-card"><span class="micro">Ataque</span><br><b>${Math.round(t.stats.attack)}</b></div><div class="mini-card"><span class="micro">Meio</span><br><b>${Math.round(t.stats.mid)}</b></div><div class="mini-card"><span class="micro">Defesa</span><br><b>${Math.round(t.stats.defense)}</b></div><div class="mini-card"><span class="micro">Encaixe</span><br><b>${Math.round(t.stats.fit||0)}</b></div><div class="mini-card"><span class="micro">Entrosamento</span><br><b>${Math.round(t.stats.chemistry||0)}</b></div></div><div class="toolbar"><button class="btn-primary" onclick="startNextMatch()">Jogar partida</button>${t.mode==='elifoot'?'<button onclick="openSquadManager()">Montar equipa</button>':''}<button onclick="closeTournament()">Fechar</button></div></div></div>`}

function pickFinalVenue(){return sample(FINAL_VENUES)||{country:'Brasil',stadium:'Maracanã',city:'Rio de Janeiro',capacity:'73.139'}}
function ensureFinalVenue(){const t=state.tournament;if(!t)return null;if(!t.finalVenue){t.finalVenue=pickFinalVenue();t.history=t.history||[];t.history.unshift(`Final definida: ${t.finalVenue.stadium}, ${t.finalVenue.city} (${t.finalVenue.country}).`);saveProgress()}return t.finalVenue}
function finalVenueHtml(t){const v=t&&t.finalVenue;if(!v)return '';return `<div class="final-venue-card"><div><div class="venue-kicker">Sede da final</div><div class="venue-title">${esc(v.stadium)}</div><div class="venue-meta">${esc(v.city)} · ${esc(v.country)} · capacidade ${esc(v.capacity)}</div></div><div class="venue-badge">Final única</div></div>`}
function finalVenueMiniHtml(t){const v=t&&t.finalVenue;if(!v)return '';return `<div class="mini-card"><span class="micro">Final</span><br><b>${esc(v.city)}</b></div>`}
function finalVenueLineHtml(obj){const v=obj&&(obj.venue||obj.finalVenue);if(!v)return '';return `<div class="venue-line"><b>Final única:</b> ${esc(v.stadium)} · ${esc(v.city)} · ${esc(v.country)} · capacidade ${esc(v.capacity)}</div>`}

function renderKoScreen(){const t=state.tournament,k=t.ko;if(k&&k.phase==='Final')ensureFinalVenue();const leg=k.phase==='Final'?'Final única':(k.leg===0?'Ida':'Volta');const home=(k.phase==='Final'||k.leg===1)?'LaBestia':opponentLabel(k.opp),away=(k.phase==='Final'||k.leg===1)?opponentLabel(k.opp):'LaBestia';const dossier=matchDossierHtml({opp:k.opp,home:k.phase==='Final'||k.leg===1,neutral:k.phase==='Final',venue:k.phase==='Final'?t.finalVenue:null},'balanced');$('tournamentContent').innerHTML=`<div class="campaign"><div class="panel"><h3>Mata-mata</h3>${specialMessageHtml(t)}${finalTwistHtml(t)}${k.phase==='Final'?finalVenueHtml(t):''}<div class="phase">${k.phase} · ${leg}</div><div class="next-card"><div class="versus">${esc(home)} x ${esc(away)}</div><div class="meta">Rival nota ${k.opp.rating} · ${modeName(t.mode)}${k.phase==='Final'&&t.finalVenue?` · ${esc(t.finalVenue.city)}`:''}</div></div>${dossier}<p class="small">${aggregateText(k)}</p><div class="toolbar"><button class="btn-primary" onclick="startNextMatch()">Jogar partida</button>${t.mode==='elifoot'?'<button onclick="openSquadManager()">Montar equipa</button>':''}</div></div><div class="panel"><h3>Campanha</h3>${historyHtml(t.history)}</div></div>`}
function psgStarterAverage(opp=worldOpponent()){const a=opp.starters||[];return a.length?Math.round(avg(a.map(p=>p.rating||opp.rating||95))):Math.round(opp.startingAverage||opp.rating||95)}
function psgSquadHtml(opp=worldOpponent()){const starters=opp.starters||[],squad=opp.squad||[];const starterRows=starters.map(p=>`<div class="psg-player"><b>${esc(p.name)}</b><span>${esc(POS_LABEL[p.pos]||p.pos)} · OVR ${p.rating}${p.traits?` · ${p.traits.map(esc).join(' · ')}`:''}</span></div>`).join('');const squadRows=squad.map(p=>`<span>${esc(p.name)} <small>${esc(p.pos||'')}</small></span>`).join('');return `<div class="psg-squad"><h4>Provável XI, média ${psgStarterAverage(opp)}</h4><div class="psg-starters">${starterRows}</div><h4>Elenco relacionado</h4><div class="psg-full-list">${squadRows}</div></div>`}
function worldIntroHtml(opp=worldOpponent()){return `<div class="world-hero"><div class="world-kicker">Depois da Glória Eterna</div><div class="world-title">Final do Mundial contra o PSG</div><p>O Cruzeiro de LaBestia conquistou a Libertadores. Agora pode encarar o Paris Saint-Germain em campo neutro. O PSG tem rating ${opp.rating} e XI inicial com média ${psgStarterAverage(opp)}: muito difícil, mas não impossível.</p></div>`}
function renderWorldReadyScreen(){const t=state.tournament,opp=(t.world&&t.world.opp)||worldOpponent();t.world=t.world||{opp,offered:true,played:false};$('modalSub').textContent='Campeão da Libertadores · desafio mundial disponível';$('tournamentContent').innerHTML=`${worldIntroHtml(opp)}<div class="campaign"><div class="panel"><h3>Convite para o Mundial</h3><p class="small"><b>LaBestia x ${esc(opponentLabel(opp))}</b><br>Final única contra um adversário europeu de média 95. A Libertadores já é sua, mas o mundo ainda cobra.</p>${psgSquadHtml(opp)}<div class="toolbar"><button class="btn-primary" onclick="startWorldChallenge()">Jogar final do Mundial</button>${t.mode==='elifoot'?'<button onclick="openSquadManager()">Montar equipa</button>':''}<button onclick="skipWorldChallenge()">Encerrar como campeão da Libertadores</button></div></div><div class="panel"><h3>Campanha até aqui</h3>${finalVenueHtml(t)}${historyHtml(t.history)}</div></div>`;saveProgress()}
function startWorldChallenge(){const t=state.tournament;if(!t)return;const opp=(t.world&&t.world.opp)||worldOpponent();t.world={opp,offered:true,played:false};t.stage='world';t.match=null;t.history.unshift('Mundial: a Besta aceitou o desafio contra o PSG.');saveProgress();renderCampaign()}
function skipWorldChallenge(){const t=state.tournament;if(!t)return;t.stage='over';t.outcome='Campeão da Libertadores. A Glória Eterna é celeste.';t.history.unshift('Mundial: a Besta recusou o convite e encerrou a campanha como campeã da América.');saveProgress();renderCampaign()}
function renderWorldScreen(){const t=state.tournament,opp=(t.world&&t.world.opp)||worldOpponent();const dossier=matchDossierHtml({opp,home:true,neutral:true,phase:'Mundial'},'balanced');$('modalSub').textContent='Final do Mundial · LaBestia x PSG';$('tournamentContent').innerHTML=`${worldIntroHtml(opp)}<div class="campaign"><div class="panel"><h3>Final do Mundial</h3><div class="next-card"><div class="versus">LaBestia x ${esc(opponentLabel(opp))}</div><div class="meta">Campo neutro · rival nota ${opp.rating} · média XI ${psgStarterAverage(opp)} · ${modeName(t.mode)}</div></div>${dossier}<div class="toolbar"><button class="btn-primary" onclick="startNextMatch()">Jogar final do Mundial</button>${t.mode==='elifoot'?'<button onclick="openSquadManager()">Montar equipa</button>':''}</div></div><div class="panel"><h3>PSG</h3>${psgSquadHtml(opp)}</div></div>`}
function worldLineHtml(m){return m&&m.opp&&m.opp.worldFinal?`<div class="final-venue-card world"><div class="venue-badge">Mundial</div><div><b>Final do Mundial de Clubes</b><span>Campo neutro · ${esc(opponentLabel(m.opp))} · média XI ${psgStarterAverage(m.opp)}</span></div></div>`:''}
function finishWorldDecision(won,penalties=false,score=null){const t=state.tournament;if(!t)return;const opp=(t.world&&t.world.opp)||worldOpponent();t.world=t.world||{opp};t.world.played=true;t.world.won=!!won;t.world.decidedByPenalties=!!penalties;if(score)t.world.penalties=score;if(won){t.outcome='Campeão da Libertadores e campeão do Mundo. A Besta derrubou o PSG.';t.history.unshift(`Mundial: LaBestia venceu ${opponentLabel(opp)}${penalties?' nos pênaltis':''}. O mundo ficou azul.`)}else{t.outcome='Campeão da Libertadores, vice do Mundial diante do PSG.';t.history.unshift(`Mundial: ${opponentLabel(opp)} segurou a Besta${penalties?' nos pênaltis':''}. A América foi azul, mas o mundo cobrou.`)}t.stage='over';t.match=null}
function worldResultHtml(t){const w=t&&t.world;if(!w||!w.played)return '';const opp=w.opp||worldOpponent();const score=w.score?`<br><b>Placar:</b> LaBestia ${w.score.user} x ${w.score.opp} ${esc(opponentLabel(opp))}`:'';const pen=w.penalties?`<br><b>Pênaltis:</b> LaBestia ${w.penalties.u} x ${w.penalties.o} ${esc(opponentLabel(opp))}`:'';return `<div class="world-result ${w.won?'win':'loss'}"><div class="world-kicker">Final do Mundial</div><div class="world-title">${w.won?'O mundo é azul':'A Europa cobrou'}</div><p>${w.won?'A Besta venceu o PSG e juntou América e Mundo.':'A Besta conquistou a América, mas caiu diante do PSG no desafio mundial.'}${score}${pen}</p></div>`}

function aggregateText(k){if(!k.scores.length)return 'Confronto ainda sem gols.';let u=0,o=0;k.scores.forEach(s=>{u+=s.user;o+=s.opp});return `Agregado: LaBestia ${u} x ${o} ${opponentLabel(k.opp)}`}
function applyFinalTwist(){const t=state.tournament;if(!t||t.finalTwistApplied)return;const slots=filled();if(!slots.length)return;const slot=sample(slots);const p=slot.player;const gain=Math.random()<.5;const delta=gain?10:-10;const plus=[`${p.name} sonhou que marcaria um hat-trick.`,`${p.name} viu uma raposa na rua e acredita estar com sorte.`,`${p.name} está vestindo sua cueca da sorte.`,`${p.name} começou a namorar a Paola Oliveira e ela pediu o título.`];const minus=[`${p.name} perdeu todo o dinheiro no Tigrinho e não dormiu à noite.`,`${p.name} está nervoso, deu caganeira.`,`${p.name} chutou uma macumba sem querer.`,`${p.name} já assinou com um clube árabe e quer se preservar.`];const before=p.adjusted||p.rating||80;const after=clamp(before+delta,45,99);p.adjusted=after;p.finalTwist=true;p.finalDelta=delta;t.stats=teamStats();t.finalTwistApplied=true;t.finalTwist={name:p.name,delta,before,after,gain,text:sample(gain?plus:minus)};t.history.unshift(`Final: ${p.name} ${gain?'ganhou':'perdeu'} 10 pontos de overall antes da decisão.`)}
function finalTwistHtml(t){if(!t||!t.finalTwist)return '';const f=t.finalTwist;return `<div class="final-twist-card ${f.gain?'gain':'loss'}"><div class="twist-kicker">Evento aleatório da final</div><div class="twist-title">${esc(f.name)} <span class="twist-delta">${f.delta>0?'+10':'-10'}</span></div><div class="twist-text">${esc(f.text)}<br><b>Overall na final:</b> ${f.before} → ${f.after}</div></div>`}
function startNextMatch(){const t=state.tournament;t.specialMessage=null;triggerRandomMoraleEvent();if(t.stage==='group'){const n=t.schedule[t.roundIndex];t.match={opp:n.opp,home:n.userHome,neutral:false,round:n.round,phase:'Grupo',events:[],minute:0,hg:0,ag:0,started:false,done:false,other:n}}else if(t.stage==='world'){const opp=(t.world&&t.world.opp)||worldOpponent();t.match={opp,home:true,neutral:true,worldFinal:true,round:0,phase:'Mundial',events:[],minute:0,hg:0,ag:0,started:false,done:false}}else{const k=t.ko;t.match={opp:k.opp,home:k.phase==='Final'||k.leg===1,neutral:k.phase==='Final',venue:k.phase==='Final'?ensureFinalVenue():null,round:0,phase:k.phase,events:[],minute:0,hg:0,ag:0,started:false,done:false}}renderCampaign()}
function strengths(match,tacticKey='balanced'){
  const t=state.tournament,st=t.stats,tc=TACTICS[tacticKey]||TACTICS.balanced;
  const id=st.identity||teamTraitIdentity(filled());
  const sc=id.scores||{};
  const hb=match.neutral?0:(match.home?2:-2),ob=match.neutral?0:(match.home?-2:2),worldAtk=match.opp&&match.opp.worldFinal?2:0,worldDef=match.opp&&match.opp.worldFinal?1:0,chemBoost=((st.chemistry||80)-85)*.08,moraleBoost=((t.morale??80)-80)*.06,sub=match.subBoost||{atk:0,def:0,tempo:0,late:0};
  const createBoost=traitMod(sc.creation,.075)+traitMod(sc.transition,.035);
  const finishBoost=traitMod(sc.finishing,.050);
  const defendBoost=traitMod(sc.defending,.070)+traitMod(sc.aerial,.030)+traitMod(sc.leadership,.025);
  const tempoBoost=traitMod(sc.transition,.006)+traitMod(sc.creation,.003);
  const lateBoost=traitMod(sc.leadership,.004);
  return {ua:st.attack*.48+st.mid*.22+st.overall*.30+tc.atk+hb+chemBoost+moraleBoost+createBoost+(sub.atk||0),ud:st.defense*.55+st.mid*.20+st.overall*.25+tc.def+hb+chemBoost+moraleBoost+defendBoost+(sub.def||0),oa:match.opp.rating+ob+worldAtk,od:match.opp.rating+ob+worldDef,tempo:tc.tempo+(sub.tempo||0)+tempoBoost,late:tc.late+(sub.late||0)+lateBoost,chemBoost,moraleBoost,subBoost:sub,identity:id,finishBoost,setPieceBoost:traitMod(sc.setPiece,.05),aerialBoost:traitMod(sc.aerial,.04)}
}
function edgeLabel(x){if(x>=8)return 'vantagem clara';if(x>=3)return 'leve vantagem';if(x<=-8)return 'risco alto';if(x<=-3)return 'atenção';return 'equilíbrio'}
function matchDossierHtml(match,tacticKey='balanced'){if(!state.tournament||!match||!match.opp)return '';const st=state.tournament.stats,s=strengths(match,tacticKey),opp=match.opp.rating;const atk=Math.round(s.ua-s.od),def=Math.round(s.ud-s.oa),fit=Math.round(st.fit||0),chem=Math.round(st.chemistry||0),id=st.identity||teamTraitIdentity(filled()),sc=id.scores||{};let trend='Jogo parelho. A América vai decidir nos detalhes.';if(atk>=5&&def>=0)trend='A Besta deve criar bastante. Se não se abrir atrás, é favorita.';else if(def<=-6)trend='Rival tem caminho para machucar a defesa. Atenção aos eventos decisivos.';else if(atk<=-4)trend='Vai faltar espaço para criar. Eficiência será obrigação.';else if(fit<70)trend='O talento existe, mas o encaixe baixo aumenta o risco de zebra.';if(sc.finishing<60)trend+=' Falta finalizador: pode criar e não matar.';else if(sc.finishing>=86)trend+=' A finalização da Besta é um trunfo.';if(sc.creation<60)trend+=' A criação é curta, o jogo pode travar.';if(sc.defending>=86)trend+=' Defesa com características fortes para segurar pressão.';if(chem>=95)trend+=' O bloco de década aumenta o entrosamento.';if(match.neutral&&match.venue)trend+=` Final em campo neutro: ${match.venue.stadium}, ${match.venue.city}.`;if(match.opp&&match.opp.worldFinal)trend+=` Desafio mundial: PSG tem média ${psgStarterAverage(match.opp)} no XI e força europeia de elite.`;return `<div class="dossier-card"><div class="dossier-kicker">Dossiê do confronto</div><div class="dossier-title">LaBestia ${Math.round(st.overall)} x ${esc(opponentLabel(match.opp))} ${opp}</div><div class="dossier-grid"><div class="dossier-stat"><span>Ataque</span><b>${edgeLabel(atk)}</b></div><div class="dossier-stat"><span>Defesa</span><b>${edgeLabel(def)}</b></div><div class="dossier-stat"><span>Finalização</span><b>${sc.finishing||0}</b></div><div class="dossier-stat"><span>Criação</span><b>${sc.creation||0}</b></div><div class="dossier-stat"><span>Encaixe</span><b>${fit}</b></div><div class="dossier-stat"><span>Moral</span><b>${Math.round(state.tournament.morale??80)}</b></div></div><p class="dossier-text">${esc(trend)}</p></div>`}
function americaCobraHtml(m){if(!m||!m.done||!state.tournament)return '';const t=state.tournament,st=t.stats,s=strengths(m,m.tactic||'balanced'),ug=m.home?m.hg:m.ag,og=m.home?m.ag:m.hg,id=st.identity||teamTraitIdentity(filled()),sc=id.scores||{};const userEvents=m.events.filter(e=>e.side==='user').length,oppEvents=m.events.filter(e=>e.side==='opp').length,userGoals=m.events.filter(e=>e.side==='user'&&e.type==='goal').length,oppGoals=m.events.filter(e=>e.side==='opp'&&e.type==='goal').length;let cls=ug>og?'win':ug<og?'loss':'draw';let title=ug>og?'Por que a Besta venceu?':ug<og?'Por que a América cobrou?':'Por que ficou no detalhe?';let reasons=[];if(s.ua-s.od>=5)reasons.push('O ataque tinha vantagem real sobre a defesa rival.');else if(s.ua-s.od<=-4)reasons.push('A criação sofreu contra a força defensiva do rival.');else reasons.push('A criação ficou equilibrada, sem domínio absoluto.');if(sc.finishing<60)reasons.push('Faltou característica de Finalização, as chances pesaram mais.');else if(sc.finishing>=86)reasons.push('A Finalização alta aumentou a letalidade da Besta.');if(sc.creation<60)reasons.push('A falta de Criatividade/Passes reduziu o volume de jogo.');else if(sc.creation>=86)reasons.push('Criatividade, passes e assistência sustentaram a criação.');if(s.ud-s.oa>=4)reasons.push('A estrutura defensiva e as características de defesa seguraram bem.');else if(s.ud-s.oa<=-5)reasons.push('A defesa entrou abaixo do nível ofensivo do adversário.');if((st.fit||0)<70)reasons.push('O encaixe baixo aumentou o peso dos improvisos.');else if((st.fit||0)>=90)reasons.push('O encaixe alto deu coerência ao time.');if(sc.leadership<60)reasons.push('Faltou liderança para estabilizar o jogo quando apertou.');if(userGoals<oppGoals&&userEvents>=oppEvents)reasons.push('A Besta até apareceu no jogo, mas o rival foi mais eficiente.');if(userGoals>oppGoals&&oppEvents>userEvents)reasons.push('O rival pressionou, mas a Besta foi mais letal.');return `<div class="america-cobra-card ${cls}"><div class="cobra-kicker">A América Cobra</div><div class="cobra-title">${esc(title)}</div><div class="cobra-grid"><div class="cobra-stat"><span>Eventos</span><b>${userEvents} x ${oppEvents}</b></div><div class="cobra-stat"><span>Gols nos eventos</span><b>${userGoals} x ${oppGoals}</b></div><div class="cobra-stat"><span>Criação</span><b>${sc.creation||0}</b></div><div class="cobra-stat"><span>Finalização</span><b>${sc.finishing||0}</b></div></div><ul class="cobra-list">${reasons.slice(0,5).map(r=>`<li>${esc(r)}</li>`).join('')}</ul></div>`}

function generateEvents(match,tactic='balanced',a=1,b=90){const s=strengths(match,tactic),id=s.identity,sc=(id&&id.scores)||{};let total=Math.round(clamp(5+Math.random()*5+Math.abs(s.ua-s.oa)/16+s.tempo*7+traitMod(sc.creation,.030),4,13));let mins=[];for(let i=0;i<total;i++)mins.push(rnd(a,b));mins.sort((x,y)=>x-y);const events=[];for(const min of mins){const late=min>75?s.late:0;const userChance=clamp(.50+(s.ua-s.oa)/46+late+traitMod(sc.creation,.0025)-traitMod(sc.defending,.0012),.20,.80);const user=Math.random()<userChance;const kind=eventKindFor(user?'user':'opp',id);const atk=user?s.ua:s.oa,def=user?s.od:s.ud;let special=0;if(user){if(kind==='set')special+=s.setPieceBoost;if(kind==='cross')special+=s.aerialBoost;if(kind==='counter')special+=traitMod(sc.transition,.045);special+=s.finishBoost;}else{special-=traitMod(sc.defending,.035);special-=kind==='cross'?traitMod(sc.aerial,.035):0}const goalProb=clamp(.19+(atk-def)/150+special/100+(min>82&&tactic==='pressure'&&user?.06:0),.08,.46);if(Math.random()<goalProb){events.push({min,type:'goal',side:user?'user':'opp',kind,scorer:user?scorer():opponentHero(match.opp)})}else{events.push({min,type:'chance',side:user?'user':'opp',kind,text:chanceText(kind,user?'user':'opp',match.opp)})}}return events}
function scoreFromEvents(match,events){let hg=0,ag=0;events.filter(e=>e.type==='goal').forEach(e=>{if(e.side==='user'){if(match.home)hg++;else ag++}else{if(match.home)ag++;else hg++}});return {hg,ag}}
function matchFlash(m){
  if(!m.done) return '';
  const ug=m.home?m.hg:m.ag, og=m.home?m.ag:m.hg;
  if(ug>og) return '<div class="match-result-flash win">🏆 Vitória celeste. A Besta rugiu.</div>';
  if(ug<og) return '<div class="match-result-flash loss">🤦‍♂️ Derrota. A América cobrou caro.</div>';
  return '<div class="match-result-flash draw">⚔️ Empate duro de Libertadores.</div>';
}
function renderClassicMatch(){
  const t=state.tournament,m=t.match;
  if(!m.started){$('tournamentContent').innerHTML=matchShell(m,'<button class="btn-primary" onclick="runClassic()">Iniciar placar</button>');return}
  const home=m.home?'LaBestia':opponentLabel(m.opp),away=m.home?opponentLabel(m.opp):'LaBestia';
  $('tournamentContent').innerHTML=`<div class="live-score"><div class="live-team">${esc(home)}</div><div><div class="scoreline" id="liveScoreline">${m.hg} x ${m.ag}</div><div class="minute" id="liveMinute">${m.done?'Fim de jogo':m.minute+"'"}</div></div><div class="live-team away">${esc(away)}</div></div><div class="progress"><span id="liveProgress" style="width:${clamp(m.minute/90*100,0,100)}%"></span></div>${m.phase==='Final'?finalVenueLineHtml(m):worldLineHtml(m)}<div id="liveFlash">${matchFlash(m)}</div><div id="liveCobra">${americaCobraHtml(m)}</div><div class="event-log" id="liveEventLog">${m.events.map(e=>eventHtml(e)).join('')}</div><div class="toolbar" id="liveContinue" style="display:${m.done?'flex':'none'}"><button class="btn-primary" onclick="finishMatch()">Continuar</button></div>`;
}
function updateClassicMatchDom(){const t=state.tournament,m=t&&t.match;if(!m||!m.started)return;const score=$('liveScoreline');if(!score){renderClassicMatch();return}score.textContent=`${m.hg} x ${m.ag}`;$('liveMinute').textContent=m.done?'Fim de jogo':m.minute+"'";$('liveProgress').style.width=clamp(m.minute/90*100,0,100)+'%';$('liveEventLog').innerHTML=m.events.map(e=>eventHtml(e)).join('');$('liveFlash').innerHTML=matchFlash(m);$('liveCobra').innerHTML=americaCobraHtml(m);$('liveContinue').style.display=m.done?'flex':'none'}
function matchShell(m,buttons){const home=m.home?'LaBestia':opponentLabel(m.opp),away=m.home?opponentLabel(m.opp):'LaBestia';const venue=m.phase==='Final'?finalVenueLineHtml(m):worldLineHtml(m);return `${venue}<div class="next-card"><div class="versus">${esc(home)} x ${esc(away)}</div><div class="meta">${esc(m.phase)} · rival nota ${m.opp.rating}${m.phase==='Final'&&m.venue?` · ${esc(m.venue.city)}`:''}</div></div>${moraleEventHtml()}${matchDossierHtml(m,m.tactic||'balanced')}<div class="toolbar">${buttons}</div>`}
function runClassic(){const m=state.tournament.match;m.started=true;m.allEvents=generateEvents(m,'balanced',1,90);m.hg=0;m.ag=0;m.minute=0;m.events=[];let idx=0;renderClassicMatch();const delay=document.body.classList.contains('lite-mode')?260:180;const iv=setInterval(()=>{m.minute+=3;while(idx<m.allEvents.length&&m.allEvents[idx].min<=m.minute){const e=m.allEvents[idx++];m.events.unshift(e);if(e.type==='goal'){if(e.side==='user'){if(m.home)m.hg++;else m.ag++}else{if(m.home)m.ag++;else m.hg++}}}if(m.minute>=90){clearInterval(iv);m.minute=90;m.done=true}updateClassicMatchDom()},delay)}
function eventHtml(e){const kind=e.kind?` <small>${esc(e.kind==='set'?'bola parada':e.kind==='cross'?'cruzamento':e.kind==='counter'?'transição':'jogo apoiado')}</small>`:'';if(e.type==='goal')return `<div class="event goal">${e.min}' GOL ${e.side==='user'?'DO LABESTIA':'DO RIVAL'}${kind} · <span class="scorer">${esc(e.scorer)}</span></div>`;return `<div class="event">${e.min}'${kind} ${esc(e.text)}</div>`}

function getElifootSpeed(){const t=state.tournament;return (t&&t.elifootSpeed)||'1x'}
function elifootDelay(){return ELIFOOT_SPEEDS[getElifootSpeed()]??ELIFOOT_SPEEDS['1x']}
function isElifootLive(m){return m&&['live1','live2'].includes(m.phaseState)}
function elifootSpeedHtml(){const cur=getElifootSpeed();return `<div class="speed-card"><div><b>Tempo do jogo</b><span>Escolha a velocidade da simulação Elifoot.</span></div><div class="speed-buttons">${['1x','2x','3x','immediate'].map(v=>`<button class="${cur===v?'btn-primary':'btn-soft'}" onclick="setElifootSpeed('${v}')">${v==='immediate'?'Imediato':v}</button>`).join('')}</div></div>`}
function setElifootSpeed(v){const t=state.tournament;if(!t)return;t.elifootSpeed=v;t.history=t.history||[];saveProgress();const m=t.match;if(v==='immediate'&&isElifootLive(m)){completeElifootSegment();return}renderElifootMatch()}
function processElifootEvent(m,e){if(!m||!e)return;if(e.type==='goal'){if(e.side==='user'){if(m.home)m.hg++;else m.ag++}else{if(m.home)m.ag++;else m.hg++}}m.minute=e.min;m.events.unshift(e)}
function startElifootSegment(tac,a,b,nextState){
  const m=state.tournament.match;if(!m)return;
  clearTimeout(window._labestiaElifootTimer);
  m.phaseState=a===1?'live1':'live2';m.currentTactic=tac;m.segmentStart=a;m.segmentEnd=b;m.minute=a-1;
  m.phaseEvents=generateEvents(m,tac,a,b).sort((x,y)=>x.min-y.min);m.phaseIndex=0;
  if(!m.events)m.events=[];
  saveProgress();renderElifootMatch();
  if(elifootDelay()===0)return completeElifootSegment(nextState);
  tickElifootSegment(nextState);
}
function tickElifootSegment(nextState){
  const m=state.tournament&&state.tournament.match;if(!m||!isElifootLive(m))return;
  const delay=elifootDelay();
  if(delay===0)return completeElifootSegment(nextState);
  window._labestiaElifootTimer=setTimeout(()=>{
    const evs=m.phaseEvents||[];
    if((m.phaseIndex||0)<evs.length){processElifootEvent(m,evs[m.phaseIndex]);m.phaseIndex=(m.phaseIndex||0)+1;renderElifootMatch();tickElifootSegment(nextState)}
    else{finishElifootSegment(nextState)}
  },delay);
}
function completeElifootSegment(nextState){
  const m=state.tournament&&state.tournament.match;if(!m)return;
  clearTimeout(window._labestiaElifootTimer);
  const evs=m.phaseEvents||[];
  while((m.phaseIndex||0)<evs.length){processElifootEvent(m,evs[m.phaseIndex]);m.phaseIndex=(m.phaseIndex||0)+1}
  finishElifootSegment(nextState||(m.phaseState==='live1'?'half':'done'));
}
function finishElifootSegment(nextState){
  const m=state.tournament&&state.tournament.match;if(!m)return;
  clearTimeout(window._labestiaElifootTimer);
  m.minute=m.segmentEnd||m.minute||0;m.phaseEvents=[];m.phaseIndex=0;m.phaseState=nextState||'half';
  if(m.phaseState==='done')m.done=true;
  saveProgress();renderElifootMatch();
}
function renderElifootMatch(){
  const t=state.tournament,m=t.match;
  const speed=elifootSpeedHtml();
  if(!m.started){$('tournamentContent').innerHTML=matchShell(m,`${speed}<div class="phase">Plano inicial</div><div class="tactic-grid">${Object.entries(TACTICS).map(([k,v])=>`<button onclick="startElifoot('${k}')">${v.name}</button>`).join('')}</div><div class="toolbar"><button onclick="openSquadManager()">Montar equipa</button></div>${benchActionHtml(m)}`);return}
  let buttons='';
  if(isElifootLive(m))buttons=`<div class="toolbar"><button class="btn-soft" onclick="completeElifootSegment()">Ir para ${m.phaseState==='live1'?'o intervalo':'o fim'}</button></div>`;
  else if(m.phaseState==='half')buttons=`<div class="phase">Intervalo. Mudar postura?</div><div class="tactic-grid">${Object.entries(TACTICS).map(([k,v])=>`<button onclick="finishElifoot('${k}')">${v.name}</button>`).join('')}</div><div class="toolbar"><button onclick="openSquadManager()">Montar equipa</button></div>`;
  else if(m.done)buttons='<div class="toolbar"><button class="btn-primary" onclick="finishMatch()">Continuar</button></div>';
  const home=m.home?'LaBestia':opponentLabel(m.opp),away=m.home?opponentLabel(m.opp):'LaBestia';
  const minuteLabel=m.done?'Fim de jogo':m.phaseState==='half'?'Intervalo':isElifootLive(m)?`${m.minute||0}'`:'Ao vivo';
  $('tournamentContent').innerHTML=`${speed}<div class="live-score"><div class="live-team">${esc(home)}</div><div><div class="scoreline">${m.hg} x ${m.ag}</div><div class="minute">${minuteLabel}</div></div><div class="live-team away">${esc(away)}</div></div>${m.phase==='Final'?finalVenueLineHtml(m):worldLineHtml(m)}${matchFlash(m)}${americaCobraHtml(m)}${benchActionHtml(m)}<div class="event-log">${m.events.map(e=>eventHtml(e)).join('')}</div>${buttons}`;
}
function startElifoot(tac){const m=state.tournament.match;m.started=true;m.tactic=tac;m.hg=0;m.ag=0;m.events=[];m.subBoost={atk:0,def:0,tempo:0,late:0};m.usedBenchIds=[];m.substitutions=0;startElifootSegment(tac,1,45,'half')}
function finishElifoot(tac){const m=state.tournament.match;m.secondTactic=tac;startElifootSegment(tac,46,90,'done')}
function finishMatch(){const t=state.tournament,m=t.match;const userGoals=m.home?m.hg:m.ag,oppGoals=m.home?m.ag:m.hg;let desc=`${m.phase}: ${m.home?'LaBestia':'Fora'} ${m.hg} x ${m.ag} ${m.home?opponentLabel(m.opp):'LaBestia'}`;if(m.phase==='Final'&&m.venue)desc+=` · ${m.venue.stadium}, ${m.venue.city}`;if(m.phase==='Mundial')desc+=` · Final do Mundial`;t.history.unshift(desc);t.goalsFor=(t.goalsFor||0)+userGoals;t.goalsAgainst=(t.goalsAgainst||0)+oppGoals;t.matches=t.matches||[];const userEvents=m.events.filter(e=>e.side==='user').length,oppEvents=m.events.filter(e=>e.side==='opp').length;t.matches.push({phase:m.phase,opp:opponentLabel(m.opp),gf:userGoals,ga:oppGoals,events:m.events.length,userEvents,oppEvents});t.scorers=t.scorers||{};m.events.filter(e=>e.side==='user'&&e.type==='goal').forEach(e=>{t.scorers[e.scorer]=(t.scorers[e.scorer]||0)+1});if(userGoals>oppGoals){t.record.v++}else if(userGoals===oppGoals){t.record.e++}else t.record.d++;updateMoraleAfterMatch(userGoals,oppGoals);t.currentMoraleEvent=null;if(t.stage==='world'){t.world=t.world||{opp:m.opp};t.world.played=true;t.world.score={user:userGoals,opp:oppGoals,hg:m.hg,ag:m.ag};t.match=null;if(userGoals===oppGoals){t.stage='penalties';t.penalties=buildPenaltyShootout(m.opp,'Mundial','world');saveProgress();renderCampaign();return}finishWorldDecision(userGoals>oppGoals,false);saveProgress();renderCampaign();return}if(t.stage==='group'){const home=m.home?'LaBestia':opponentLabel(m.opp),away=m.home?opponentLabel(m.opp):'LaBestia';applyResult(t.table,home,away,m.hg,m.ag);const other=simulateOpponentGame(m.other.otherHome,m.other.otherAway);applyResult(t.table,opponentLabel(m.other.otherHome),opponentLabel(m.other.otherAway),other.hg,other.ag);t.history.unshift(`Grupo: ${opponentLabel(m.other.otherHome)} ${other.hg} x ${other.ag} ${opponentLabel(m.other.otherAway)}`);t.roundIndex++;t.match=null;if(t.roundIndex>=6){const pos=tableSorted(t.table).findIndex(r=>r.name==='LaBestia')+1;t.groupPosition=pos;if(pos<=2){t.stage='group_done'}else{t.stage='over';t.outcome=`Eliminado na fase de grupos, ${pos}º lugar.`}}}else{advanceKo(userGoals,oppGoals);t.match=null}saveProgress();renderCampaign()}
function simulateOpponentGame(a,b){const diff=a.rating-b.rating+Math.random()*8-4;let hg=diff>8?3:diff>3?2:diff<-8?0:diff<-3?1:rnd(0,2);let ag=diff<-8?3:diff<-3?2:diff>8?0:diff>3?1:rnd(0,2);return {hg,ag}}
const KO_PHASES=[['Oitavas',86,90],['Quartas',89,93],['Semifinal',91,96],['Final',94,99]];function startKnockout(){const t=state.tournament;t.stage='ko';const [phase,min,max]=KO_PHASES[0];t.ko={idx:0,phase,opp:pickOpp(min,max,t.used),leg:0,scores:[]}}
function advanceKo(user,opp){const t=state.tournament,k=t.ko;k.scores.push({user,opp});if(k.phase!=='Final'&&k.leg===0){k.leg=1;return}let ug=k.scores.reduce((a,s)=>a+s.user,0),og=k.scores.reduce((a,s)=>a+s.opp,0);if(ug===og){t.stage='penalties';t.penalties=buildPenaltyShootout();return}finishKoDecision(ug>og)}
function finishKoDecision(won){const t=state.tournament,k=t.ko;const msg=specialKoMessage(k.opp,won);if(msg){t.specialMessage=msg;t.history.unshift(`Easter egg: ${msg}`)}if(won){if(k.phase==='Final'){t.libertadoresChampion=true;t.world={opp:worldOpponent(),offered:true,played:false};t.stage='world_ready';t.outcome='Campeão da Libertadores. A Glória Eterna é celeste.';t.history.unshift('Título: LaBestia conquistou a Libertadores e recebeu convite para a final do Mundial contra o PSG.');return}k.idx++;const [phase,min,max]=KO_PHASES[k.idx];t.stage='ko';t.ko={idx:k.idx,phase,opp:pickOpp(min,max,t.used),leg:0,scores:[]};if(phase==='Final'){ensureFinalVenue();applyFinalTwist()}}else{t.stage='over';t.outcome=`Eliminado na ${k.phase} por ${opponentLabel(k.opp)}.`}}
function specialKoMessage(opp,won){const club=norm(opp.club),year=Number(opp.year)||0;if(club.includes('estudiantes')&&year===2009)return won?'TOOOOOMA, VERÓN! Demorou, mas a vingança veio, desgramado!':'Ah, não, que desgrama é essa? Perdemos de novo pra esse time feio?';if(club.includes('atletico mineiro'))return won?'hahahaha chupem essas, franguinhas de Vespasiano!':'Aí você tá de brincadeira, cumpadi, você foi moleque, MOLEQUE!';return ''}
function specialMessageHtml(t){return t&&t.specialMessage?`<div class="special-easter"><b>Easter egg desbloqueado:</b><br>${esc(t.specialMessage)}</div>`:''}
function penaltyUserTakers(){let arr=filled().map(s=>({...s.player,slotPos:s.pos}));if(!arr.length)return [{name:'LaBestia',rating:88,adjusted:88,slotPos:'ATA'}];function w(p){let v=(p.adjusted||p.rating||80);if(p.captain)v+=8;if(['ATA','PE','PD','MEI','MD','ME'].includes(p.slotPos))v+=7;if(['VOL','LD','LE'].includes(p.slotPos))v+=2;if(p.slotPos==='G')v-=8;const tr=playerTraits(p);if(tr.includes('Finalização'))v+=7;if(tr.includes('Bola parada'))v+=5;if(tr.includes('Pegador de pênaltis'))v+=6;if(tr.includes('Muralha'))v+=3;return v}return arr.sort((a,b)=>w(b)-w(a))}
function penaltyOppTakers(opp){const names=String(opp.players||'').split(';').map(x=>x.trim()).filter(Boolean);return names.length?names:[opponentLabel(opp)]}
function buildPenaltyShootout(overrideOpp=null,overridePhase=null,context='ko'){const t=state.tournament,k=t.ko||{};const opp=overrideOpp||k.opp,phase=overridePhase||k.phase||'Pênaltis';let u=0,o=0,au=0,ao=0,steps=[];const userTakers=penaltyUserTakers(),oppTakers=penaltyOppTakers(opp);const penScore=(t.stats.identity&&t.stats.identity.scores?t.stats.identity.scores.penalties:70);const up=clamp(.76+(t.stats.overall-opp.rating)*.005+traitMod(penScore,.0016),.60,.90),op=clamp(.76+(opp.rating-t.stats.overall)*.004+(opp.worldFinal?0.018:0),.62,.90);function taker(side,n){return side==='user'?userTakers[(n-1)%userTakers.length].name:oppTakers[(n-1)%oppTakers.length]}function shot(side,prob){let n;if(side==='user'){au++;n=au}else{ao++;n=ao}const goal=Math.random()<prob;if(side==='user'){if(goal)u++}else{if(goal)o++}steps.push({side,goal,u,o,taker:taker(side,n),attempt:n})}function decided(){if(au<=5&&ao<=5){const ru=5-au,ro=5-ao;if(u>o+ro)return true;if(o>u+ru)return true;return false}return au>=5&&ao>=5&&au===ao&&u!==o}for(let i=0;i<5;i++){shot('user',up);if(decided())break;shot('opp',op);if(decided())break}let guard=0;while(!decided()&&u===o&&guard<10){shot('user',up);shot('opp',op);guard++}if(!decided()&&u===o){const userWins=Math.random()<clamp(.5+(t.stats.overall-opp.rating)*.015-(opp.worldFinal?0.04:0),.32,.66);shot('user',userWins?1:0);shot('opp',userWins?0:1)}return {phase,opp,context,steps,revealed:0,running:false,done:false,userFinal:u,oppFinal:o,winner:u>o?'user':'opp'}}
function penaltyVisibleScore(p){let u=0,o=0;for(let i=0;i<Math.min(p.revealed,p.steps.length);i++){const s=p.steps[i];if(s.goal){if(s.side==='user')u++;else o++}}return {u,o}}
function penaltyRow(p,side){return p.steps.map((s,i)=>({...s,i})).filter(s=>s.side===side).map(s=>{const show=s.i<p.revealed,active=s.i===p.revealed-1?' active':'';const cls=!show?'pending':s.goal?'goal':'miss';const sym=!show?'·':s.goal?'⚽':'✕';return `<span class="penalty-shot ${cls}${active}" title="${esc(s.taker||'')}"><span class="kick-symbol">${sym}</span><span class="kick-name">${esc(s.taker||'—')}</span></span>`}).join('')}
function renderPenaltyScreen(){const t=state.tournament,p=t.penalties,sc=penaltyVisibleScore(p),opp=opponentLabel(p.opp);const next=p.steps[p.revealed];const status=p.done?(p.winner==='user'?'LaBestia venceu nos pênaltis':'LaBestia caiu nos pênaltis'):(p.running&&next?`Na bola: ${next.taker}`:(p.running?'Cobranças em andamento':'Empate no agregado. Agora é coração, bola e destino.'));const btn=p.done?`<button class="btn-primary" onclick="finishPenaltyStage()">Continuar</button>`:p.running?`<button class="btn-soft" disabled>Cobrando...</button>`:`<button class="btn-primary" onclick="startPenaltyAnimation()">Cobrar pênaltis</button>`;$('modalSub').textContent=`${p.phase} · decisão por pênaltis`;$('tournamentContent').innerHTML=`<div class="penalty-stage"><h3 class="penalty-title">Decisão por pênaltis</h3><div class="penalty-sub">${esc(p.phase)} · LaBestia x ${esc(opp)}</div><div class="penalty-scoreboard"><div class="penalty-team">LaBestia</div><div class="penalty-score">${sc.u} x ${sc.o}</div><div class="penalty-team away">${esc(opp)}</div></div><div class="penalty-rows"><div class="penalty-row"><div class="penalty-label">LaBestia</div><div class="penalty-shots">${penaltyRow(p,'user')}</div></div><div class="penalty-row"><div class="penalty-label">${esc(opp)}</div><div class="penalty-shots">${penaltyRow(p,'opp')}</div></div></div><p class="penalty-note"><b>${esc(status)}</b><br>⚽ é gol, ✕ é erro. As cobranças acabam assim que um time não puder mais alcançar o outro.</p><div class="toolbar">${btn}</div></div><div class="panel" style="margin-top:18px"><h3>Campanha</h3>${historyHtml(t.history)}</div>`}
function startPenaltyAnimation(){const t=state.tournament,p=t.penalties;if(!p||p.running)return;p.running=true;p.done=false;p.revealed=0;renderPenaltyScreen();clearInterval(window._labestiaPenaltyTimer);window._labestiaPenaltyTimer=setInterval(()=>{p.revealed++;if(p.revealed>=p.steps.length){p.revealed=p.steps.length;p.running=false;p.done=true;clearInterval(window._labestiaPenaltyTimer)}renderPenaltyScreen()},document.body.classList.contains('lite-mode')?980:760)}
function finishPenaltyStage(){const t=state.tournament,p=t.penalties;if(!p||!p.done)return;const won=p.winner==='user';if(won)t.penaltyWins=(t.penaltyWins||0)+1;t.history.unshift(`Pênaltis: LaBestia ${p.userFinal} x ${p.oppFinal} ${opponentLabel(p.opp)} — ${won?'classificação celeste':'queda cruel'}.`);t.penalties=null;if(p.context==='world'){finishWorldDecision(won,true,{u:p.userFinal,o:p.oppFinal});saveProgress();renderCampaign();return}finishKoDecision(won);saveProgress();renderCampaign()}
function restartFullFromTournament(){state.tournament=null;closeTournament();resetGame()}
function renderOver(){
  const t=state.tournament;
  const summary=campaignSummary();
  const champ=summary.champ;
  const groupFail=t.outcome.includes('fase de grupos');
  if(!t.completedSaved){
    t.completedSaved=true;
    const ranked=addRanking(summary);
    summary.score=ranked.score;
    saveLastCampaign(summary);
    clearProgress();
  }
  const ach=evaluateAchievements(summary);
  const trophySrc='assets/image-2-53bd16cdf6a5.png';
  const banner=summary.worldChampion?'A América e o Mundo são azuis':(summary.worldPlayed?'A América é azul, o mundo cobrou':(champ?'A América é azul':'A campanha terminou'));
  const scene=champ
    ? `<div class="result-scene win"><div class="result-confetti"></div><div class="tri-title">${summary.worldChampion?'O MUNDO É AZUL!':'O TRI VEIO!'}</div><div class="scene-trophy"><img src="${trophySrc}" alt="Taça Libertadores"></div><div class="scene-caption">${summary.worldChampion?'Glória Mundial!':'Glória Eterna!'}</div></div>`
    : `<div class="result-scene loss"><div class="emoji-burst loss"><span>👎</span><span>👎</span><span>👎</span><span>👎</span><span>👎</span><span>👎</span></div><div class="loss-title">A América foi cruel.</div><div class="scene-trophy"><img src="${trophySrc}" alt="Taça Libertadores"></div><div class="scene-caption">A América cobrou.</div></div>`;
  const easter=groupFail?`<div class="group-easter"><b>Easter egg desbloqueado:</b><br>Parabéns, campeão, você foi o responsável por fazer com que LaBestia caísse na fase de grupos pela primeira vez na história... Viajou demais, Zé... Cê é louco!</div>`:'';
  const newAch=ach.newOnes.length?`<div class="special-easter"><b>Conquistas desbloqueadas:</b><br>${ach.newOnes.map(a=>esc(a.name)).join(' · ')}</div>`:'';
  $('tournamentContent').innerHTML=`<div class="final-banner">${banner}</div>${scene}<div class="campaign"><div class="panel"><h3>Resumo final da Besta</h3><p class="small"><b>${esc(summary.status)}</b><br>${esc(finalVerdict(summary))}</p>${finalVenueHtml(t)}${worldResultHtml(t)}${easter}${specialMessageHtml(t)}${newAch}<div class="mini-cards summary-grid"><div class="mini-card"><span class="micro">Campanha</span><br><b>${summary.wins}V ${summary.draws}E ${summary.losses}D</b></div><div class="mini-card"><span class="micro">Gols</span><br><b>${summary.goalsFor} x ${summary.goalsAgainst}</b></div><div class="mini-card"><span class="micro">Artilheiro</span><br><b>${esc(summary.topScorer)}</b></div><div class="mini-card"><span class="micro">Força</span><br><b>${summary.overall}</b></div><div class="mini-card"><span class="micro">Encaixe</span><br><b>${summary.fit}</b></div><div class="mini-card"><span class="micro">Entrosamento</span><br><b>${summary.chemistry}</b></div>${finalVenueMiniHtml(t)}</div><div class="america-cobra-card ${champ?'win':'loss'}"><div class="cobra-kicker">A América Cobra</div><div class="cobra-title">${esc(finalVerdict(summary))}</div><ul class="cobra-list"><li>Overall mede talento. Encaixe mede coerência.</li><li>Entrosamento premia blocos históricos da mesma década.</li><li>O ranking local guardou esta campanha neste navegador.</li></ul></div><div class="toolbar"><button class="btn-primary" onclick="restartFullFromTournament()">Recomeçar draft</button><button onclick="openRanking()">Ranking</button><button onclick="closeTournament()">Fechar</button></div></div><div class="panel"><h3>Conquistas</h3>${achievementsHtml(summary)}<h3 style="margin-top:18px">Histórico</h3>${historyHtml(t.history)}</div></div>`;
}
